INSERT INTO public.category (cg_id, mode_cg) VALUES (1, 'ความรู้ทั่วไป');
INSERT INTO public.category (cg_id, mode_cg) VALUES (2, 'กลโกง/สแกมเมอร์');
INSERT INTO public.category (cg_id, mode_cg) VALUES (3, 'ความปลอดภัยไอที');
INSERT INTO public.category (cg_id, mode_cg) VALUES (4, 'กฎหมายไซเบอร์');
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (1, 'easy', 'รหัส OTP (เลข 6 หลัก) บอกคนอื่นได้ไหม?', 'OTP เปรียบเสมือนกุญแจเข้าตู้เซฟ ธนาคารไม่มีนโยบายขอ OTP ลูกค้าเด็ดขาด', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (2, 'easy', 'ถ้ามีเบอร์แปลกโทรมาขู่ว่า "คุณทำผิดกฎหมาย" ควรทำไง?', 'ตำรวจจริงจะไม่โทรมาสอบสวนทางโทรศัพท์ หรือให้โอนเงินเพื่อตรวจสอบเส้นทาง', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (3, 'easy', 'รหัสผ่านธนาคาร ควรตั้งยังไงให้ปลอดภัย?', 'รหัสที่ปลอดภัยควรผสมตัวเลขที่คาดเดายาก และไม่ควรใช้ข้อมูลส่วนตัวที่หาได้ง่าย', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (4, 'easy', 'SMS ส่งมาว่า "คุณได้รับเงินกู้/เงินฟรี" ให้กดลิงก์?', 'SMS แนบลิงก์ส่วนใหญ่เป็น Phishing หลอกให้กรอกข้อมูล หรือติดตั้งแอปดูดเงิน', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (5, 'easy', 'บัตรประชาชน ถ่ายรูปส่งให้คนแปลกหน้าได้ไหม?', 'มิจฉาชีพอาจนำภาพบัตรประชาชนไปสวมรอยทำธุรกรรมผิดกฎหมาย หรือเปิดบัญชีม้า', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (6, 'easy', 'เจอของขายในเน็ต "ราคาถูกผิดปกติ"?', 'ของดีและถูกมากไม่มีจริง มักเป็นกลลวงให้รีบโอนเงินแล้วหนีหาย', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (7, 'easy', 'ถ้าจะโอนเงินซื้อของ ต้องเช็คอะไรก่อน?', 'ควรนำชื่อ-นามสกุล หรือเลขบัญชีไปค้นใน Google หรือเว็บ Blacklistseller ก่อนเสมอ', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (8, 'easy', 'แอปธนาคาร ควรให้ใครรู้รหัสเข้า?', 'รหัสผ่านทางการเงินเป็นความลับสูงสุด ห้ามบอกใครแม้แต่คนใกล้ชิด', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (9, 'easy', 'เล่นเฟซบุ๊กอยู่ดีๆ มีคนทักมาขอยืมเงิน?', 'เพื่อนอาจโดนแฮกเฟซบุ๊ก ต้องโทรเช็คเสียงหรือวิดีโอคอลเพื่อยืนยันตัวตนเสมอ', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (10, 'easy', 'ไปรษณีย์โทรมาว่า "มีพัสดุตกค้าง" ให้โอนค่าปรับ?', 'ไปรษณีย์ไทยไม่มีนโยบายโทรแจ้งพัสดุตกค้างแล้วให้โอนเงินค่าปรับ', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (11, 'easy', 'ATM กดเงินเสร็จแล้ว ลืมบัตรไว้ที่ตู้?', 'ควรรีบแจ้งธนาคารเพื่ออายัดบัตร ก่อนที่คนอื่นจะนำไปกดเงินต่อ', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (12, 'easy', 'Wi-Fi สาธารณะ (Free WiFi) ควรใช้ทำธุรกรรมการเงินไหม?', 'Wi-Fi สาธารณะมีความเสี่ยงสูงที่จะถูกแฮกเกอร์ขโมยข้อมูลรหัสผ่าน', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (13, 'easy', 'ถ้ามือถือหาย สิ่งแรกที่ควรทำเกี่ยวกับแอปธนาคาร?', 'ต้องรีบโทรหา Call Center ธนาคารเพื่อปลดล็อกการใช้งานแอปในเครื่องเก่าทันที', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (14, 'easy', 'ใครคือคนที่ไว้ใจได้ที่สุดในการทำธุรกรรม?', 'ตนเป็นที่พึ่งแห่งตน อย่าเชื่อคำชักจูงของคนอื่นง่ายๆ ในเรื่องเงิน', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (15, 'easy', 'รหัส PIN 6 หลัก ห้ามตั้งแบบไหน?', 'รหัสที่เรียงกันหรือซ้ำกัน (Pattern) คาดเดาง่ายที่สุดสำหรับโจร', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (16, 'easy', 'ข้อความ "คุณเป็นผู้โชคดีได้รับรางวัล" เชื่อได้ไหม?', 'ของฟรีไม่มีในโลก มักเป็นอุบายหลอกให้เราเสียเงินค่าธรรมเนียมหรือภาษีก่อน', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (17, 'easy', 'เจอ QR Code แปะตามเสาไฟฟ้า บอกว่าสแกนรับเงิน?', 'QR Code ในที่สาธารณะอาจนำไปสู่เว็บอันตรายหรือหลอกติดตั้งแอป', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (18, 'easy', 'เวลาพิมพ์รหัสผ่านในที่สาธารณะ ควรทำไง?', 'ควรระวังคนแอบมอง (Shoulder Surfing) หรือกล้องวงจรปิดที่อาจบันทึกภาพมือเรา', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (19, 'easy', 'ถ้ามีคนโอนเงินผิดมาเข้าบัญชีเรา ควรทำไง?', 'การโอนคืนเองเสี่ยงเป็นส่วนหนึ่งของการฟอกเงิน ให้ธนาคารเป็นคนดำเนินการดึงเงินคืน', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (20, 'easy', 'ปุ่ม "Remember Password" (จำรหัสผ่าน) บนคอมสาธารณะ?', 'ถ้ากดจำรหัสไว้ คนที่มาใช้งานต่อจะเข้าบัญชีเราได้ทันที', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (21, 'easy', 'รูปโปรไฟล์สาวสวย ทักมาคุยเรื่องลงทุน?', 'มุกคลาสสิก ใช้รูปปลอมหลอกให้รักแล้วชวนลงทุนในแอปปลอม', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (22, 'easy', 'การตั้งค่าความเป็นส่วนตัวใน Facebook ควรเป็นแบบไหน?', 'การเปิด Public ทำให้มิจฉาชีพเก็บข้อมูลส่วนตัวเราไปสวมรอยได้ง่าย', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (23, 'easy', 'ได้รับอีเมลภาษาอังกฤษ แปลกๆ บอกว่าบัญชีมีปัญหา?', 'มักเป็น Phishing Email ให้สังเกตที่อยู่ผู้ส่ง (Sender Address) ว่าถูกต้องไหม', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (24, 'easy', 'เว็บที่ขึ้นต้นด้วย http:// (ไม่มี s) ปลอดภัยไหม?', 'HTTP ไม่มีการเข้ารหัสข้อมูล ไม่ควรกรอกรหัสผ่านหรือข้อมูลบัตรเครดิต', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (25, 'easy', 'ถ้าสงสัยว่าโดนหลอก โทรปรึกษาใครได้?', '1441 คือศูนย์ปฏิบัติการแก้ไขปัญหาอาชญากรรมออนไลน์ (AOC) โดยตรง', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (26, 'easy', 'การอัปเดตแอปธนาคารเป็นเวอร์ชันล่าสุด ดีไหม?', 'ควรอัปเดตเสมอเพื่อให้ได้รับระบบรักษาความปลอดภัยล่าสุด', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (27, 'easy', 'รหัสหลังบัตรเครดิต (CVV) บอกใครได้บ้าง?', 'CVV ใช้ยืนยันการจ่ายเงินออนไลน์ ถ้าใครรู้ก็เอาไปรูดซื้อของได้เลย', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (28, 'easy', 'สลิปโอนเงินปลอม ดูยังไง?', 'สลิปปลอมมักเกิดจากการตัดต่อ ฟอนต์จะไม่เนียน หรือเวลาสแกน QR จะไม่ตรงกับข้อมูล', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (29, 'easy', 'ลงทุน 1,000 ได้คืน 5,000 ใน 1 ชั่วโมง?', 'ผลตอบแทนที่สูงเกินจริงและได้เร็วเกินไป คือลักษณะของแชร์ลูกโซ่', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (30, 'easy', 'ถ้าเพื่อนส่งลิงก์มาในแชท แต่ภาษาพูดดูแปลกๆ?', 'เพื่อนอาจโดนแฮกแล้วส่งลิงก์ไวรัสมาให้เรา ต้องยืนยันตัวตนก่อนเสมอ', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (31, 'medium', 'ถ้ามือถือค้าง จอดับ หรือกดอะไรไม่ได้ (โดนรีโมท) ต้องทำไง?', 'ต้องตัดการเชื่อมต่อทันทีเพื่อหยุดโจรไม่ให้ควบคุมเครื่องได้ต่อ', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (32, 'medium', 'เบอร์สายด่วน ไว้อายัดบัญชีธนาคารทันที คือเบอร์อะไร?', '1441 คือศูนย์ AOC สายด่วนปราบปรามอาชญากรรมทางเทคโนโลยี โทรได้ 24 ชม.', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (33, 'medium', 'แอปดูดเงิน มักจะเข้ามาในเครื่องเราทางไหน?', 'ส่วนใหญ่มาจากการหลอกให้กดลิงก์ดาวน์โหลดไฟล์ .apk นอก Store', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (34, 'medium', 'Romance Scam (หลอกให้รัก) มักจะมามุกไหน?', 'ใช้โปรไฟล์ปลอมตีสนิทให้เหยื่อรัก แล้วอ้างเหตุผลสารพัดเพื่อขอยืมเงิน', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (35, 'medium', 'หลอกขายของแบบ ABC (โกงสามเหลี่ยม) คือ?', 'โจรเป็นคนกลางหลอกเราโอนเงินให้ร้านจริง แล้วโจรไปรับของจากร้านจริงแทน', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (36, 'medium', 'ถ้าเผลอกดลิงก์แปลกๆ ไปแล้ว สิ่งแรกที่ควรทำ?', 'ตัดเน็ตเพื่อหยุดการดาวน์โหลดหรือส่งข้อมูล แล้วรีบเช็คเครื่องทันที', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (37, 'medium', 'ร้านค้าออนไลน์ที่ "ปิดคอมเมนต์" หรือ "เปลี่ยนชื่อเพจบ่อยๆ"?', 'ปิดคอมเมนต์เพื่อปิดบังคนมาประจาน และเปลี่ยนชื่อเพื่อหนีประวัติการโกง', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (38, 'medium', 'กดเงินไม่ใช้บัตร (Cardless) ถ้ามีคนโทรมาขอรหัส?', 'รหัสกดเงินให้ใครไม่ได้เด็ดขาด เพราะเขาสามารถไปกดเงินสดที่ตู้ได้ทันที', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (39, 'medium', 'Deepfake คือเทคโนโลยีที่โจรเอามาใช้อย่างไร?', 'AI สามารถสร้างภาพเคลื่อนไหวและเสียงเลียนแบบบุคคลอื่นได้เนียนมาก', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (40, 'medium', 'วิธีเช็คว่าคนที่วิดีโอคอลมา เป็นตัวจริงหรือ Deepfake?', 'Deepfake มักจะมีจุดบกพร่องเมื่อมีการเคลื่อนไหวรวดเร็วผ่านใบหน้า', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (41, 'medium', '2FA (Two-Factor Authentication) คืออะไร?', 'เช่น ใส่รหัสผ่าน + รหัส OTP ช่วยป้องกันบัญชีได้ดีขึ้นมาก', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (42, 'medium', 'การอนุญาต Accessibility Service ใน Android เสี่ยงอย่างไร?', 'ฟีเจอร์ช่วยเหลือคนพิการ แต่มิจฉาชีพใช้ช่องโหว่นี้ในการรีโมทควบคุมเครื่องเหยื่อ', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (43, 'medium', 'Phishing Website มักจะมีลักษณะอย่างไร?', 'เช่น facbook.com (หายไปตัว e) หรือ kbank-secure.com (ชื่อยาวผิดปกติ)', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (44, 'medium', 'บัญชีม้า คืออะไร?', 'การรับจ้างเปิดบัญชีให้คนอื่น ผิดกฎหมายและมีโทษจำคุก', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (45, 'medium', 'Hybrid Scam คือกลโกงแบบไหน?', 'ผสมผสานระหว่าง Romance Scam (ความรัก) + Investment Scam (การลงทุน)', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (46, 'medium', 'Social Engineering (วิศวกรรมสังคม) คือ?', 'ไม่ได้แฮกที่ระบบ แต่แฮกที่ "คน" เช่น โทรมาหลอกให้ตกใจเพื่อขอรหัส', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (47, 'medium', 'ถ้าต้องการเช็คประวัติคนโกง ควรเช็คที่เว็บไหน?', 'เป็นเว็บฐานข้อมูลกลางที่คนมักจะมาแจ้งเตือนรายชื่อคนโกง', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (48, 'medium', 'PDPA เกี่ยวข้องกับอะไร?', 'Personal Data Protection Act กฎหมายที่ดูแลการเก็บและใช้ข้อมูลส่วนตัวของเรา', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (49, 'medium', 'การตั้งรหัสผ่านแบบไหน ปลอดภัยที่สุด?', 'ควรยาว มีตัวเลข ผสมสัญลักษณ์ และไม่เป็นคำที่มีในพจนานุกรม (Passphrase)', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (50, 'medium', 'Clickbait (คลิกเบต) อันตรายอย่างไร?', 'มักใช้คำกระตุ้นความอยากรู้อยากเห็น เพื่อล่อให้เข้าไปในเว็บที่ไม่ปลอดภัย', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (51, 'medium', 'Ransomware (มัลแวร์เรียกค่าไถ่) ทำงานอย่างไร?', 'จะเข้ารหัสไฟล์งานของเรา ทำให้เปิดไม่ได้ จนกว่าจะจ่ายเงินให้แฮกเกอร์', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (52, 'medium', 'ทำไมไม่ควรชาร์จมือถือกับตู้สาธารณะที่ไม่รู้จัก (Juice Jacking)?', 'พอร์ต USB สามารถส่งถ่ายข้อมูลได้ แฮกเกอร์อาจดัดแปลงตู้ชาร์จเพื่อขโมยข้อมูล', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (53, 'medium', 'Digital Footprint คืออะไร?', 'ทุกสิ่งที่เราโพสต์ คอมเมนต์ หรือเข้าชม จะถูกบันทึกไว้และอาจย้อนกลับมาทำร้ายเราได้', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (54, 'medium', 'Sextortion คือการข่มขู่แบบไหน?', 'มักเกิดจากการวิดีโอคอลเสียว หรือแฮกภาพส่วนตัวไปเรียกค่าไถ่', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (55, 'medium', 'Money Mule แปลว่าอะไร?', 'คนที่เป็นทางผ่านของเงินที่ได้มาอย่างผิดกฎหมาย', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (56, 'medium', 'ถ้าเจอข่าวปลอม (Fake News) ควรทำไง?', 'เช็คจากสำนักข่าวที่น่าเชื่อถือ หรือศูนย์ต่อต้านข่าวปลอม (Anti-Fake News Center)', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (57, 'medium', 'Vishing (Voice Phishing) คือ?', 'ใช้เสียง (Voice) โทรมาหลอกลวง เช่น แก๊งคอลเซ็นเตอร์', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (58, 'medium', 'Smishing คืออะไร?', 'SMS + Phishing = หลอกทางข้อความมือถือ', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (59, 'medium', 'Incognito Mode (โหมดไม่ระบุตัวตน) ช่วยอะไร?', 'ช่วยแค่ไม่ให้คนมาใช้คอมต่อเห็นประวัติเรา แต่ ISP และเว็บปลายทางยังเห็นเราอยู่', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (60, 'medium', 'Biometric Authentication คือ?', 'ใช้ลักษณะทางกายภาพระบุตัวตน ซึ่งปลอมแปลงยากกว่ารหัสผ่าน', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (61, 'hard', 'ซิมผี หรือ ซิมม้า คืออะไร?', 'ใช้เพื่อปกปิดตัวตนในการโทรหลอกลวง หรือรับ OTP เปิดบัญชีม้า', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (62, 'hard', 'ถ้ามี SMS แนบลิงก์ ชื่อผู้ส่งเป็นชื่อธนาคารเลย เชื่อได้ไหม?', 'SMS Sender Name สามารถปลอมแปลงได้ (Spoofing) อย่าเชื่อชื่อที่เห็น', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (63, 'hard', 'QR Code ดูดเงิน มีจริงไหม?', 'QR อาจพาไปเว็บ Phishing หลอกให้กรอกข้อมูล หรือดาวน์โหลดมัลแวร์', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (64, 'hard', 'การรับจ้างเปิดบัญชีม้า มีความผิดไหม?', 'ตาม พ.ร.ก. มาตรการป้องกันฯ อาชญากรรมทางเทคโนโลยี มีโทษหนักทั้งจำทั้งปรับ', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (65, 'hard', 'กดลิงก์แล้วไม่ได้ทำอะไร เงินหายได้ไหม?', 'ลิงก์เป็นแค่ประตู แต่เงินจะหายเมื่อเราติดตั้งแอปโจร หรือกรอกรหัสให้เขา', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (66, 'hard', 'Clickbait (พาดหัวข่าวน่ากด) อันตรายยังไง?', 'มักใช้คำกระตุ้นความอยากรู้อยากเห็น เพื่อล่อเข้าไปเว็บที่มีอันตราย', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (67, 'hard', 'ทำไมโจรถึงชอบให้เราโอนแบบ Crypto (เหรียญดิจิทัล)?', 'ธุรกรรมคริปโตมีความเป็นส่วนตัวสูง ยากต่อการอายัดและติดตามเส้นทางเงิน', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (68, 'hard', 'การตั้งค่ามือถือ "ห้ามติดตั้งแอปจากแหล่งไม่รู้จัก" ช่วยอะไร?', 'เป็นการล็อคประตูบ้าน ไม่ให้โจรเอาแอปอันตรายมาติดตั้งในเครื่องเรา', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (69, 'hard', 'ถ้าคนร้ายรู้วันเกิดและเลขบัตรประชาชนเรา เขาเอาไปทำอะไรได้?', 'เป็นข้อมูลพื้นฐานที่ใช้ยืนยันตัวตน หรือเดารหัสผ่านได้ง่าย', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (70, 'hard', 'เว็บบน Google ที่ขึ้นคำว่า "Ad" หรือ "โฆษณา" เชื่อได้ไหม?', 'โจรยอมจ่ายเงินซื้อโฆษณาเพื่อให้เว็บปลอมของตัวเองขึ้นอันดับ 1 บน Google', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (71, 'hard', 'Zero-Day Exploit คืออะไร?', 'ช่องโหว่ที่ผู้พัฒนาเพิ่งรู้และยังแก้ไขไม่ทัน เป็นช่วงที่อันตรายที่สุด', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (72, 'hard', 'DDoS Attack คือการโจมตีแบบไหน?', 'Distributed Denial of Service การใช้คอมพิวเตอร์จำนวนมากถล่มเว็บให้ใช้งานไม่ได้', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (73, 'hard', 'VPN (Virtual Private Network) ช่วยเรื่องความปลอดภัยอย่างไร?', 'สร้างท่อข้อมูลส่วนตัวที่ปลอดภัย ป้องกันการดักจับข้อมูลระหว่างทาง', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (74, 'hard', 'End-to-End Encryption (E2EE) สำคัญอย่างไร?', 'แม้แต่ผู้ให้บริการ (เช่น LINE/WhatsApp) ก็อ่านข้อความเราไม่ได้', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (75, 'hard', 'Brute Force Attack คือ?', 'ใช้โปรแกรมลองผิดลองถูกรหัสผ่านเป็นล้านๆ ครั้งเพื่อเจาะระบบ', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (76, 'hard', 'Spyware มีหน้าที่หลักคือ?', 'สายลับที่ฝังตัวในเครื่องเพื่อขโมยรหัสผ่านหรือข้อมูลบัตรเครดิต', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (77, 'hard', 'Botnet คืออะไร?', 'เครื่องที่ติดมัลแวร์และถูกสั่งการพร้อมกันเพื่อโจมตีเป้าหมายอื่น', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (78, 'hard', 'SQL Injection เป็นการโจมตีที่ส่วนไหน?', 'การใส่โค้ดคำสั่งหลอกลวงเข้าไปในช่องกรอกข้อมูลเพื่อเจาะฐานข้อมูลเว็บ', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (79, 'hard', 'Man-in-the-Middle (MitM) Attack คือ?', 'แฮกเกอร์แทรกตัวอยู่ตรงกลางการสื่อสารเพื่อดักฟังหรือแก้ไขข้อมูล', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (80, 'hard', 'Cookie ในทางคอมพิวเตอร์คืออะไร?', 'ใช้จำการตั้งค่าหรือการล็อกอิน แต่ถ้าถูกขโมย (Session Hijacking) ก็อันตราย', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (81, 'hard', 'การทำ Sandboxing คืออะไร?', 'ทดสอบไฟล์ต้องสงสัยในกล่องปิดตาย ถ้าเป็นไวรัสก็จะไม่ลามออกมาข้างนอก', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (82, 'hard', 'Keylogger คือโปรแกรมประเภทไหน?', 'บันทึกทุกปุ่มที่เรากด เพื่อขโมยรหัสผ่านหรือข้อความแชท', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (83, 'hard', 'Rootkit อันตรายอย่างไร?', 'มัลแวร์ที่ฝังรากลึกและซ่อนตัวจากการตรวจจับของ Antivirus ทั่วไป', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (84, 'hard', 'Social Engineering แตกต่างจากการแฮกทั่วไปยังไง?', 'ใช้การหลอกลวง ตีสนิท หรือข่มขู่ ให้เหยื่อบอกรหัสผ่านเอง', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (85, 'hard', 'Whaling Phishing คือการโจมตีใคร?', 'การตกปลาตัวใหญ่ (Whale) เน้นหลอก CEO หรือ CFO เพื่อให้โอนเงินจำนวนมาก', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (86, 'hard', 'Trojan Horse (ม้าโทรจัน) ต่างจากไวรัสยังไง?', 'ต้องหลอกให้ผู้ใช้กดรันเอง โดยซ่อนมาในเกมเถื่อนหรือโปรแกรมแคร็ก', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (87, 'hard', 'Blockchain ช่วยเรื่องความปลอดภัยยังไง?', 'ความโปร่งใสและแก้ไขข้อมูลย้อนหลังไม่ได้ ทำให้ยากต่อการปลอมแปลงธุรกรรม', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (88, 'hard', 'SIM Swapping คือการโจมตีแบบไหน?', 'โจรขโมยเบอร์เราไปใส่เครื่องตัวเอง เพื่อรับ OTP แฮกบัญชีธนาคาร', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (89, 'hard', 'Honey Pot ในทาง Cyber Security คือ?', 'ระบบจำลองที่สร้างขึ้นเพื่อล่อให้แฮกเกอร์โจมตี เพื่อศึกษาพฤติกรรมหรือถ่วงเวลา', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (90, 'hard', 'Cross-Site Scripting (XSS) คือ?', 'ทำให้เว็บที่ดูปลอดภัยกลายเป็นตัวแพร่กระจายสคริปต์ขโมยข้อมูล', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (91, 'easy', 'รหัส OTP (เลข 6 หลัก) บอกคนอื่นได้ไหม?', 'OTP เปรียบเสมือนกุญแจเข้าตู้เซฟ ธนาคารไม่มีนโยบายขอ OTP ลูกค้าเด็ดขาด', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (92, 'easy', 'ถ้ามีเบอร์แปลกโทรมาขู่ว่า "คุณทำผิดกฎหมาย" ควรทำไง?', 'ตำรวจจริงจะไม่โทรมาสอบสวนทางโทรศัพท์ หรือให้โอนเงินเพื่อตรวจสอบเส้นทาง', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (93, 'easy', 'รหัสผ่านธนาคาร ควรตั้งยังไงให้ปลอดภัย?', 'รหัสที่ปลอดภัยควรผสมตัวเลขที่คาดเดายาก และไม่ควรใช้ข้อมูลส่วนตัวที่หาได้ง่าย', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (94, 'easy', 'SMS ส่งมาว่า "คุณได้รับเงินกู้/เงินฟรี" ให้กดลิงก์?', 'SMS แนบลิงก์ส่วนใหญ่เป็น Phishing หลอกให้กรอกข้อมูล หรือติดตั้งแอปดูดเงิน', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (95, 'easy', 'บัตรประชาชน ถ่ายรูปส่งให้คนแปลกหน้าได้ไหม?', 'มิจฉาชีพอาจนำภาพบัตรประชาชนไปสวมรอยทำธุรกรรมผิดกฎหมาย หรือเปิดบัญชีม้า', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (96, 'easy', 'เจอของขายในเน็ต "ราคาถูกผิดปกติ"?', 'ของดีและถูกมากไม่มีจริง มักเป็นกลลวงให้รีบโอนเงินแล้วหนีหาย', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (97, 'easy', 'ถ้าจะโอนเงินซื้อของ ต้องเช็คอะไรก่อน?', 'ควรนำชื่อ-นามสกุล หรือเลขบัญชีไปค้นใน Google หรือเว็บ Blacklistseller ก่อนเสมอ', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (145, 'medium', 'Money Mule แปลว่าอะไร?', 'คนที่เป็นทางผ่านของเงินที่ได้มาอย่างผิดกฎหมาย', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (98, 'easy', 'แอปธนาคาร ควรให้ใครรู้รหัสเข้า?', 'รหัสผ่านทางการเงินเป็นความลับสูงสุด ห้ามบอกใครแม้แต่คนใกล้ชิด', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (99, 'easy', 'เล่นเฟซบุ๊กอยู่ดีๆ มีคนทักมาขอยืมเงิน?', 'เพื่อนอาจโดนแฮกเฟซบุ๊ก ต้องโทรเช็คเสียงหรือวิดีโอคอลเพื่อยืนยันตัวตนเสมอ', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (100, 'easy', 'ไปรษณีย์โทรมาว่า "มีพัสดุตกค้าง" ให้โอนค่าปรับ?', 'ไปรษณีย์ไทยไม่มีนโยบายโทรแจ้งพัสดุตกค้างแล้วให้โอนเงินค่าปรับ', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (101, 'easy', 'ATM กดเงินเสร็จแล้ว ลืมบัตรไว้ที่ตู้?', 'ควรรีบแจ้งธนาคารเพื่ออายัดบัตร ก่อนที่คนอื่นจะนำไปกดเงินต่อ', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (102, 'easy', 'Wi-Fi สาธารณะ (Free WiFi) ควรใช้ทำธุรกรรมการเงินไหม?', 'Wi-Fi สาธารณะมีความเสี่ยงสูงที่จะถูกแฮกเกอร์ขโมยข้อมูลรหัสผ่าน', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (103, 'easy', 'ถ้ามือถือหาย สิ่งแรกที่ควรทำเกี่ยวกับแอปธนาคาร?', 'ต้องรีบโทรหา Call Center ธนาคารเพื่อปลดล็อกการใช้งานแอปในเครื่องเก่าทันที', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (104, 'easy', 'ใครคือคนที่ไว้ใจได้ที่สุดในการทำธุรกรรม?', 'ตนเป็นที่พึ่งแห่งตน อย่าเชื่อคำชักจูงของคนอื่นง่ายๆ ในเรื่องเงิน', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (105, 'easy', 'รหัส PIN 6 หลัก ห้ามตั้งแบบไหน?', 'รหัสที่เรียงกันหรือซ้ำกัน (Pattern) คาดเดาง่ายที่สุดสำหรับโจร', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (106, 'easy', 'ข้อความ "คุณเป็นผู้โชคดีได้รับรางวัล" เชื่อได้ไหม?', 'ของฟรีไม่มีในโลก มักเป็นอุบายหลอกให้เราเสียเงินค่าธรรมเนียมหรือภาษีก่อน', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (107, 'easy', 'เจอ QR Code แปะตามเสาไฟฟ้า บอกว่าสแกนรับเงิน?', 'QR Code ในที่สาธารณะอาจนำไปสู่เว็บอันตรายหรือหลอกติดตั้งแอป', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (108, 'easy', 'เวลาพิมพ์รหัสผ่านในที่สาธารณะ ควรทำไง?', 'ควรระวังคนแอบมอง (Shoulder Surfing) หรือกล้องวงจรปิดที่อาจบันทึกภาพมือเรา', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (109, 'easy', 'ถ้ามีคนโอนเงินผิดมาเข้าบัญชีเรา ควรทำไง?', 'การโอนคืนเองเสี่ยงเป็นส่วนหนึ่งของการฟอกเงิน ให้ธนาคารเป็นคนดำเนินการดึงเงินคืน', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (110, 'easy', 'ปุ่ม "Remember Password" (จำรหัสผ่าน) บนคอมสาธารณะ?', 'ถ้ากดจำรหัสไว้ คนที่มาใช้งานต่อจะเข้าบัญชีเราได้ทันที', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (111, 'easy', 'รูปโปรไฟล์สาวสวย ทักมาคุยเรื่องลงทุน?', 'มุกคลาสสิก ใช้รูปปลอมหลอกให้รักแล้วชวนลงทุนในแอปปลอม', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (112, 'easy', 'การตั้งค่าความเป็นส่วนตัวใน Facebook ควรเป็นแบบไหน?', 'การเปิด Public ทำให้มิจฉาชีพเก็บข้อมูลส่วนตัวเราไปสวมรอยได้ง่าย', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (113, 'easy', 'ได้รับอีเมลภาษาอังกฤษ แปลกๆ บอกว่าบัญชีมีปัญหา?', 'มักเป็น Phishing Email ให้สังเกตที่อยู่ผู้ส่ง (Sender Address) ว่าถูกต้องไหม', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (114, 'easy', 'เว็บที่ขึ้นต้นด้วย http:// (ไม่มี s) ปลอดภัยไหม?', 'HTTP ไม่มีการเข้ารหัสข้อมูล ไม่ควรกรอกรหัสผ่านหรือข้อมูลบัตรเครดิต', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (115, 'easy', 'ถ้าสงสัยว่าโดนหลอก โทรปรึกษาใครได้?', '1441 คือศูนย์ปฏิบัติการแก้ไขปัญหาอาชญากรรมออนไลน์ (AOC) โดยตรง', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (116, 'easy', 'การอัปเดตแอปธนาคารเป็นเวอร์ชันล่าสุด ดีไหม?', 'ควรอัปเดตเสมอเพื่อให้ได้รับระบบรักษาความปลอดภัยล่าสุด', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (117, 'easy', 'รหัสหลังบัตรเครดิต (CVV) บอกใครได้บ้าง?', 'CVV ใช้ยืนยันการจ่ายเงินออนไลน์ ถ้าใครรู้ก็เอาไปรูดซื้อของได้เลย', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (118, 'easy', 'สลิปโอนเงินปลอม ดูยังไง?', 'สลิปปลอมมักเกิดจากการตัดต่อ ฟอนต์จะไม่เนียน หรือเวลาสแกน QR จะไม่ตรงกับข้อมูล', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (119, 'easy', 'ลงทุน 1,000 ได้คืน 5,000 ใน 1 ชั่วโมง?', 'ผลตอบแทนที่สูงเกินจริงและได้เร็วเกินไป คือลักษณะของแชร์ลูกโซ่', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (120, 'easy', 'ถ้าเพื่อนส่งลิงก์มาในแชท แต่ภาษาพูดดูแปลกๆ?', 'เพื่อนอาจโดนแฮกแล้วส่งลิงก์ไวรัสมาให้เรา ต้องยืนยันตัวตนก่อนเสมอ', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (121, 'medium', 'ถ้ามือถือค้าง จอดับ หรือกดอะไรไม่ได้ (โดนรีโมท) ต้องทำไง?', 'ต้องตัดการเชื่อมต่อทันทีเพื่อหยุดโจรไม่ให้ควบคุมเครื่องได้ต่อ', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (122, 'medium', 'เบอร์สายด่วน ไว้อายัดบัญชีธนาคารทันที คือเบอร์อะไร?', '1441 คือศูนย์ AOC สายด่วนปราบปรามอาชญากรรมทางเทคโนโลยี โทรได้ 24 ชม.', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (123, 'medium', 'แอปดูดเงิน มักจะเข้ามาในเครื่องเราทางไหน?', 'ส่วนใหญ่มาจากการหลอกให้กดลิงก์ดาวน์โหลดไฟล์ .apk นอก Store', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (124, 'medium', 'Romance Scam (หลอกให้รัก) มักจะมามุกไหน?', 'ใช้โปรไฟล์ปลอมตีสนิทให้เหยื่อรัก แล้วอ้างเหตุผลสารพัดเพื่อขอยืมเงิน', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (125, 'medium', 'หลอกขายของแบบ ABC (โกงสามเหลี่ยม) คือ?', 'โจรเป็นคนกลางหลอกเราโอนเงินให้ร้านจริง แล้วโจรไปรับของจากร้านจริงแทน', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (126, 'medium', 'ถ้าเผลอกดลิงก์แปลกๆ ไปแล้ว สิ่งแรกที่ควรทำ?', 'ตัดเน็ตเพื่อหยุดการดาวน์โหลดหรือส่งข้อมูล แล้วรีบเช็คเครื่องทันที', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (127, 'medium', 'ร้านค้าออนไลน์ที่ "ปิดคอมเมนต์" หรือ "เปลี่ยนชื่อเพจบ่อยๆ"?', 'ปิดคอมเมนต์เพื่อปิดบังคนมาประจาน และเปลี่ยนชื่อเพื่อหนีประวัติการโกง', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (128, 'medium', 'กดเงินไม่ใช้บัตร (Cardless) ถ้ามีคนโทรมาขอรหัส?', 'รหัสกดเงินให้ใครไม่ได้เด็ดขาด เพราะเขาสามารถไปกดเงินสดที่ตู้ได้ทันที', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (129, 'medium', 'Deepfake คือเทคโนโลยีที่โจรเอามาใช้อย่างไร?', 'AI สามารถสร้างภาพเคลื่อนไหวและเสียงเลียนแบบบุคคลอื่นได้เนียนมาก', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (130, 'medium', 'วิธีเช็คว่าคนที่วิดีโอคอลมา เป็นตัวจริงหรือ Deepfake?', 'Deepfake มักจะมีจุดบกพร่องเมื่อมีการเคลื่อนไหวรวดเร็วผ่านใบหน้า', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (131, 'medium', '2FA (Two-Factor Authentication) คืออะไร?', 'เช่น ใส่รหัสผ่าน + รหัส OTP ช่วยป้องกันบัญชีได้ดีขึ้นมาก', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (132, 'medium', 'การอนุญาต Accessibility Service ใน Android เสี่ยงอย่างไร?', 'ฟีเจอร์ช่วยเหลือคนพิการ แต่มิจฉาชีพใช้ช่องโหว่นี้ในการรีโมทควบคุมเครื่องเหยื่อ', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (133, 'medium', 'Phishing Website มักจะมีลักษณะอย่างไร?', 'เช่น facbook.com (หายไปตัว e) หรือ kbank-secure.com (ชื่อยาวผิดปกติ)', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (134, 'medium', 'บัญชีม้า คืออะไร?', 'การรับจ้างเปิดบัญชีให้คนอื่น ผิดกฎหมายและมีโทษจำคุก', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (135, 'medium', 'Hybrid Scam คือกลโกงแบบไหน?', 'ผสมผสานระหว่าง Romance Scam (ความรัก) + Investment Scam (การลงทุน)', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (136, 'medium', 'Social Engineering (วิศวกรรมสังคม) คือ?', 'ไม่ได้แฮกที่ระบบ แต่แฮกที่ "คน" เช่น โทรมาหลอกให้ตกใจเพื่อขอรหัส', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (137, 'medium', 'ถ้าต้องการเช็คประวัติคนโกง ควรเช็คที่เว็บไหน?', 'เป็นเว็บฐานข้อมูลกลางที่คนมักจะมาแจ้งเตือนรายชื่อคนโกง', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (138, 'medium', 'PDPA เกี่ยวข้องกับอะไร?', 'Personal Data Protection Act กฎหมายที่ดูแลการเก็บและใช้ข้อมูลส่วนตัวของเรา', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (139, 'medium', 'การตั้งรหัสผ่านแบบไหน ปลอดภัยที่สุด?', 'ควรยาว มีตัวเลข ผสมสัญลักษณ์ และไม่เป็นคำที่มีในพจนานุกรม (Passphrase)', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (140, 'medium', 'Clickbait (คลิกเบต) อันตรายอย่างไร?', 'มักใช้คำกระตุ้นความอยากรู้อยากเห็น เพื่อล่อให้เข้าไปในเว็บที่ไม่ปลอดภัย', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (141, 'medium', 'Ransomware (มัลแวร์เรียกค่าไถ่) ทำงานอย่างไร?', 'จะเข้ารหัสไฟล์งานของเรา ทำให้เปิดไม่ได้ จนกว่าจะจ่ายเงินให้แฮกเกอร์', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (142, 'medium', 'ทำไมไม่ควรชาร์จมือถือกับตู้สาธารณะที่ไม่รู้จัก (Juice Jacking)?', 'พอร์ต USB สามารถส่งถ่ายข้อมูลได้ แฮกเกอร์อาจดัดแปลงตู้ชาร์จเพื่อขโมยข้อมูล', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (143, 'medium', 'Digital Footprint คืออะไร?', 'ทุกสิ่งที่เราโพสต์ คอมเมนต์ หรือเข้าชม จะถูกบันทึกไว้และอาจย้อนกลับมาทำร้ายเราได้', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (144, 'medium', 'Sextortion คือการข่มขู่แบบไหน?', 'มักเกิดจากการวิดีโอคอลเสียว หรือแฮกภาพส่วนตัวไปเรียกค่าไถ่', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (146, 'medium', 'ถ้าเจอข่าวปลอม (Fake News) ควรทำไง?', 'เช็คจากสำนักข่าวที่น่าเชื่อถือ หรือศูนย์ต่อต้านข่าวปลอม (Anti-Fake News Center)', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (147, 'medium', 'Vishing (Voice Phishing) คือ?', 'ใช้เสียง (Voice) โทรมาหลอกลวง เช่น แก๊งคอลเซ็นเตอร์', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (148, 'medium', 'Smishing คืออะไร?', 'SMS + Phishing = หลอกทางข้อความมือถือ', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (149, 'medium', 'Incognito Mode (โหมดไม่ระบุตัวตน) ช่วยอะไร?', 'ช่วยแค่ไม่ให้คนมาใช้คอมต่อเห็นประวัติเรา แต่ ISP และเว็บปลายทางยังเห็นเราอยู่', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (150, 'medium', 'Biometric Authentication คือ?', 'ใช้ลักษณะทางกายภาพระบุตัวตน ซึ่งปลอมแปลงยากกว่ารหัสผ่าน', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (151, 'hard', 'ซิมผี หรือ ซิมม้า คืออะไร?', 'ใช้เพื่อปกปิดตัวตนในการโทรหลอกลวง หรือรับ OTP เปิดบัญชีม้า', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (152, 'hard', 'ถ้ามี SMS แนบลิงก์ ชื่อผู้ส่งเป็นชื่อธนาคารเลย เชื่อได้ไหม?', 'SMS Sender Name สามารถปลอมแปลงได้ (Spoofing) อย่าเชื่อชื่อที่เห็น', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (153, 'hard', 'QR Code ดูดเงิน มีจริงไหม?', 'QR อาจพาไปเว็บ Phishing หลอกให้กรอกข้อมูล หรือดาวน์โหลดมัลแวร์', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (154, 'hard', 'การรับจ้างเปิดบัญชีม้า มีความผิดไหม?', 'ตาม พ.ร.ก. มาตรการป้องกันฯ อาชญากรรมทางเทคโนโลยี มีโทษหนักทั้งจำทั้งปรับ', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (155, 'hard', 'กดลิงก์แล้วไม่ได้ทำอะไร เงินหายได้ไหม?', 'ลิงก์เป็นแค่ประตู แต่เงินจะหายเมื่อเราติดตั้งแอปโจร หรือกรอกรหัสให้เขา', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (156, 'hard', 'Clickbait (พาดหัวข่าวน่ากด) อันตรายยังไง?', 'มักใช้คำกระตุ้นความอยากรู้อยากเห็น เพื่อล่อเข้าไปเว็บที่มีอันตราย', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (157, 'hard', 'ทำไมโจรถึงชอบให้เราโอนแบบ Crypto (เหรียญดิจิทัล)?', 'ธุรกรรมคริปโตมีความเป็นส่วนตัวสูง ยากต่อการอายัดและติดตามเส้นทางเงิน', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (158, 'hard', 'การตั้งค่ามือถือ "ห้ามติดตั้งแอปจากแหล่งไม่รู้จัก" ช่วยอะไร?', 'เป็นการล็อคประตูบ้าน ไม่ให้โจรเอาแอปอันตรายมาติดตั้งในเครื่องเรา', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (159, 'hard', 'ถ้าคนร้ายรู้วันเกิดและเลขบัตรประชาชนเรา เขาเอาไปทำอะไรได้?', 'เป็นข้อมูลพื้นฐานที่ใช้ยืนยันตัวตน หรือเดารหัสผ่านได้ง่าย', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (160, 'hard', 'เว็บบน Google ที่ขึ้นคำว่า "Ad" หรือ "โฆษณา" เชื่อได้ไหม?', 'โจรยอมจ่ายเงินซื้อโฆษณาเพื่อให้เว็บปลอมของตัวเองขึ้นอันดับ 1 บน Google', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (161, 'hard', 'Zero-Day Exploit คืออะไร?', 'ช่องโหว่ที่ผู้พัฒนาเพิ่งรู้และยังแก้ไขไม่ทัน เป็นช่วงที่อันตรายที่สุด', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (162, 'hard', 'DDoS Attack คือการโจมตีแบบไหน?', 'Distributed Denial of Service การใช้คอมพิวเตอร์จำนวนมากถล่มเว็บให้ใช้งานไม่ได้', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (163, 'hard', 'VPN (Virtual Private Network) ช่วยเรื่องความปลอดภัยอย่างไร?', 'สร้างท่อข้อมูลส่วนตัวที่ปลอดภัย ป้องกันการดักจับข้อมูลระหว่างทาง', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (164, 'hard', 'End-to-End Encryption (E2EE) สำคัญอย่างไร?', 'แม้แต่ผู้ให้บริการ (เช่น LINE/WhatsApp) ก็อ่านข้อความเราไม่ได้', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (165, 'hard', 'Brute Force Attack คือ?', 'ใช้โปรแกรมลองผิดลองถูกรหัสผ่านเป็นล้านๆ ครั้งเพื่อเจาะระบบ', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (166, 'hard', 'Spyware มีหน้าที่หลักคือ?', 'สายลับที่ฝังตัวในเครื่องเพื่อขโมยรหัสผ่านหรือข้อมูลบัตรเครดิต', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (167, 'hard', 'Botnet คืออะไร?', 'เครื่องที่ติดมัลแวร์และถูกสั่งการพร้อมกันเพื่อโจมตีเป้าหมายอื่น', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (168, 'hard', 'SQL Injection เป็นการโจมตีที่ส่วนไหน?', 'การใส่โค้ดคำสั่งหลอกลวงเข้าไปในช่องกรอกข้อมูลเพื่อเจาะฐานข้อมูลเว็บ', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (169, 'hard', 'Man-in-the-Middle (MitM) Attack คือ?', 'แฮกเกอร์แทรกตัวอยู่ตรงกลางการสื่อสารเพื่อดักฟังหรือแก้ไขข้อมูล', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (170, 'hard', 'Cookie ในทางคอมพิวเตอร์คืออะไร?', 'ใช้จำการตั้งค่าหรือการล็อกอิน แต่ถ้าถูกขโมย (Session Hijacking) ก็อันตราย', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (171, 'hard', 'การทำ Sandboxing คืออะไร?', 'ทดสอบไฟล์ต้องสงสัยในกล่องปิดตาย ถ้าเป็นไวรัสก็จะไม่ลามออกมาข้างนอก', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (172, 'hard', 'Keylogger คือโปรแกรมประเภทไหน?', 'บันทึกทุกปุ่มที่เรากด เพื่อขโมยรหัสผ่านหรือข้อความแชท', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (173, 'hard', 'Rootkit อันตรายอย่างไร?', 'มัลแวร์ที่ฝังรากลึกและซ่อนตัวจากการตรวจจับของ Antivirus ทั่วไป', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (174, 'hard', 'Social Engineering แตกต่างจากการแฮกทั่วไปยังไง?', 'ใช้การหลอกลวง ตีสนิท หรือข่มขู่ ให้เหยื่อบอกรหัสผ่านเอง', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (175, 'hard', 'Whaling Phishing คือการโจมตีใคร?', 'การตกปลาตัวใหญ่ (Whale) เน้นหลอก CEO หรือ CFO เพื่อให้โอนเงินจำนวนมาก', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (176, 'hard', 'Trojan Horse (ม้าโทรจัน) ต่างจากไวรัสยังไง?', 'ต้องหลอกให้ผู้ใช้กดรันเอง โดยซ่อนมาในเกมเถื่อนหรือโปรแกรมแคร็ก', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (177, 'hard', 'Blockchain ช่วยเรื่องความปลอดภัยยังไง?', 'ความโปร่งใสและแก้ไขข้อมูลย้อนหลังไม่ได้ ทำให้ยากต่อการปลอมแปลงธุรกรรม', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (178, 'hard', 'SIM Swapping คือการโจมตีแบบไหน?', 'โจรขโมยเบอร์เราไปใส่เครื่องตัวเอง เพื่อรับ OTP แฮกบัญชีธนาคาร', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (179, 'hard', 'Honey Pot ในทาง Cyber Security คือ?', 'ระบบจำลองที่สร้างขึ้นเพื่อล่อให้แฮกเกอร์โจมตี เพื่อศึกษาพฤติกรรมหรือถ่วงเวลา', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (180, 'hard', 'Cross-Site Scripting (XSS) คือ?', 'ทำให้เว็บที่ดูปลอดภัยกลายเป็นตัวแพร่กระจายสคริปต์ขโมยข้อมูล', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (181, 'easy', 'รหัส OTP (เลข 6 หลัก) บอกคนอื่นได้ไหม?', 'OTP เปรียบเสมือนกุญแจเข้าตู้เซฟ ธนาคารไม่มีนโยบายขอ OTP ลูกค้าเด็ดขาด', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (182, 'easy', 'ถ้ามีเบอร์แปลกโทรมาขู่ว่า "คุณทำผิดกฎหมาย" ควรทำไง?', 'ตำรวจจริงจะไม่โทรมาสอบสวนทางโทรศัพท์ หรือให้โอนเงินเพื่อตรวจสอบเส้นทาง', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (183, 'easy', 'รหัสผ่านธนาคาร ควรตั้งยังไงให้ปลอดภัย?', 'รหัสที่ปลอดภัยควรผสมตัวเลขที่คาดเดายาก และไม่ควรใช้ข้อมูลส่วนตัวที่หาได้ง่าย', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (184, 'easy', 'SMS ส่งมาว่า "คุณได้รับเงินกู้/เงินฟรี" ให้กดลิงก์?', 'SMS แนบลิงก์ส่วนใหญ่เป็น Phishing หลอกให้กรอกข้อมูล หรือติดตั้งแอปดูดเงิน', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (185, 'easy', 'บัตรประชาชน ถ่ายรูปส่งให้คนแปลกหน้าได้ไหม?', 'มิจฉาชีพอาจนำภาพบัตรประชาชนไปสวมรอยทำธุรกรรมผิดกฎหมาย หรือเปิดบัญชีม้า', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (186, 'easy', 'เจอของขายในเน็ต "ราคาถูกผิดปกติ"?', 'ของดีและถูกมากไม่มีจริง มักเป็นกลลวงให้รีบโอนเงินแล้วหนีหาย', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (187, 'easy', 'ถ้าจะโอนเงินซื้อของ ต้องเช็คอะไรก่อน?', 'ควรนำชื่อ-นามสกุล หรือเลขบัญชีไปค้นใน Google หรือเว็บ Blacklistseller ก่อนเสมอ', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (188, 'easy', 'แอปธนาคาร ควรให้ใครรู้รหัสเข้า?', 'รหัสผ่านทางการเงินเป็นความลับสูงสุด ห้ามบอกใครแม้แต่คนใกล้ชิด', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (189, 'easy', 'เล่นเฟซบุ๊กอยู่ดีๆ มีคนทักมาขอยืมเงิน?', 'เพื่อนอาจโดนแฮกเฟซบุ๊ก ต้องโทรเช็คเสียงหรือวิดีโอคอลเพื่อยืนยันตัวตนเสมอ', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (190, 'easy', 'ไปรษณีย์โทรมาว่า "มีพัสดุตกค้าง" ให้โอนค่าปรับ?', 'ไปรษณีย์ไทยไม่มีนโยบายโทรแจ้งพัสดุตกค้างแล้วให้โอนเงินค่าปรับ', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (191, 'easy', 'ATM กดเงินเสร็จแล้ว ลืมบัตรไว้ที่ตู้?', 'ควรรีบแจ้งธนาคารเพื่ออายัดบัตร ก่อนที่คนอื่นจะนำไปกดเงินต่อ', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (192, 'easy', 'Wi-Fi สาธารณะ (Free WiFi) ควรใช้ทำธุรกรรมการเงินไหม?', 'Wi-Fi สาธารณะมีความเสี่ยงสูงที่จะถูกแฮกเกอร์ขโมยข้อมูลรหัสผ่าน', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (193, 'easy', 'ถ้ามือถือหาย สิ่งแรกที่ควรทำเกี่ยวกับแอปธนาคาร?', 'ต้องรีบโทรหา Call Center ธนาคารเพื่อปลดล็อกการใช้งานแอปในเครื่องเก่าทันที', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (194, 'easy', 'ใครคือคนที่ไว้ใจได้ที่สุดในการทำธุรกรรม?', 'ตนเป็นที่พึ่งแห่งตน อย่าเชื่อคำชักจูงของคนอื่นง่ายๆ ในเรื่องเงิน', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (195, 'easy', 'รหัส PIN 6 หลัก ห้ามตั้งแบบไหน?', 'รหัสที่เรียงกันหรือซ้ำกัน (Pattern) คาดเดาง่ายที่สุดสำหรับโจร', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (196, 'easy', 'ข้อความ "คุณเป็นผู้โชคดีได้รับรางวัล" เชื่อได้ไหม?', 'ของฟรีไม่มีในโลก มักเป็นอุบายหลอกให้เราเสียเงินค่าธรรมเนียมหรือภาษีก่อน', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (197, 'easy', 'เจอ QR Code แปะตามเสาไฟฟ้า บอกว่าสแกนรับเงิน?', 'QR Code ในที่สาธารณะอาจนำไปสู่เว็บอันตรายหรือหลอกติดตั้งแอป', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (198, 'easy', 'เวลาพิมพ์รหัสผ่านในที่สาธารณะ ควรทำไง?', 'ควรระวังคนแอบมอง (Shoulder Surfing) หรือกล้องวงจรปิดที่อาจบันทึกภาพมือเรา', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (199, 'easy', 'ถ้ามีคนโอนเงินผิดมาเข้าบัญชีเรา ควรทำไง?', 'การโอนคืนเองเสี่ยงเป็นส่วนหนึ่งของการฟอกเงิน ให้ธนาคารเป็นคนดำเนินการดึงเงินคืน', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (200, 'easy', 'ปุ่ม "Remember Password" (จำรหัสผ่าน) บนคอมสาธารณะ?', 'ถ้ากดจำรหัสไว้ คนที่มาใช้งานต่อจะเข้าบัญชีเราได้ทันที', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (201, 'easy', 'รูปโปรไฟล์สาวสวย ทักมาคุยเรื่องลงทุน?', 'มุกคลาสสิก ใช้รูปปลอมหลอกให้รักแล้วชวนลงทุนในแอปปลอม', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (202, 'easy', 'การตั้งค่าความเป็นส่วนตัวใน Facebook ควรเป็นแบบไหน?', 'การเปิด Public ทำให้มิจฉาชีพเก็บข้อมูลส่วนตัวเราไปสวมรอยได้ง่าย', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (203, 'easy', 'ได้รับอีเมลภาษาอังกฤษ แปลกๆ บอกว่าบัญชีมีปัญหา?', 'มักเป็น Phishing Email ให้สังเกตที่อยู่ผู้ส่ง (Sender Address) ว่าถูกต้องไหม', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (204, 'easy', 'เว็บที่ขึ้นต้นด้วย http:// (ไม่มี s) ปลอดภัยไหม?', 'HTTP ไม่มีการเข้ารหัสข้อมูล ไม่ควรกรอกรหัสผ่านหรือข้อมูลบัตรเครดิต', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (205, 'easy', 'ถ้าสงสัยว่าโดนหลอก โทรปรึกษาใครได้?', '1441 คือศูนย์ปฏิบัติการแก้ไขปัญหาอาชญากรรมออนไลน์ (AOC) โดยตรง', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (206, 'easy', 'การอัปเดตแอปธนาคารเป็นเวอร์ชันล่าสุด ดีไหม?', 'ควรอัปเดตเสมอเพื่อให้ได้รับระบบรักษาความปลอดภัยล่าสุด', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (207, 'easy', 'รหัสหลังบัตรเครดิต (CVV) บอกใครได้บ้าง?', 'CVV ใช้ยืนยันการจ่ายเงินออนไลน์ ถ้าใครรู้ก็เอาไปรูดซื้อของได้เลย', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (208, 'easy', 'สลิปโอนเงินปลอม ดูยังไง?', 'สลิปปลอมมักเกิดจากการตัดต่อ ฟอนต์จะไม่เนียน หรือเวลาสแกน QR จะไม่ตรงกับข้อมูล', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (209, 'easy', 'ลงทุน 1,000 ได้คืน 5,000 ใน 1 ชั่วโมง?', 'ผลตอบแทนที่สูงเกินจริงและได้เร็วเกินไป คือลักษณะของแชร์ลูกโซ่', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (210, 'easy', 'ถ้าเพื่อนส่งลิงก์มาในแชท แต่ภาษาพูดดูแปลกๆ?', 'เพื่อนอาจโดนแฮกแล้วส่งลิงก์ไวรัสมาให้เรา ต้องยืนยันตัวตนก่อนเสมอ', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (211, 'medium', 'ถ้ามือถือค้าง จอดับ หรือกดอะไรไม่ได้ (โดนรีโมท) ต้องทำไง?', 'ต้องตัดการเชื่อมต่อทันทีเพื่อหยุดโจรไม่ให้ควบคุมเครื่องได้ต่อ', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (212, 'medium', 'เบอร์สายด่วน ไว้อายัดบัญชีธนาคารทันที คือเบอร์อะไร?', '1441 คือศูนย์ AOC สายด่วนปราบปรามอาชญากรรมทางเทคโนโลยี โทรได้ 24 ชม.', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (213, 'medium', 'แอปดูดเงิน มักจะเข้ามาในเครื่องเราทางไหน?', 'ส่วนใหญ่มาจากการหลอกให้กดลิงก์ดาวน์โหลดไฟล์ .apk นอก Store', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (214, 'medium', 'Romance Scam (หลอกให้รัก) มักจะมามุกไหน?', 'ใช้โปรไฟล์ปลอมตีสนิทให้เหยื่อรัก แล้วอ้างเหตุผลสารพัดเพื่อขอยืมเงิน', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (215, 'medium', 'หลอกขายของแบบ ABC (โกงสามเหลี่ยม) คือ?', 'โจรเป็นคนกลางหลอกเราโอนเงินให้ร้านจริง แล้วโจรไปรับของจากร้านจริงแทน', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (216, 'medium', 'ถ้าเผลอกดลิงก์แปลกๆ ไปแล้ว สิ่งแรกที่ควรทำ?', 'ตัดเน็ตเพื่อหยุดการดาวน์โหลดหรือส่งข้อมูล แล้วรีบเช็คเครื่องทันที', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (217, 'medium', 'ร้านค้าออนไลน์ที่ "ปิดคอมเมนต์" หรือ "เปลี่ยนชื่อเพจบ่อยๆ"?', 'ปิดคอมเมนต์เพื่อปิดบังคนมาประจาน และเปลี่ยนชื่อเพื่อหนีประวัติการโกง', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (218, 'medium', 'กดเงินไม่ใช้บัตร (Cardless) ถ้ามีคนโทรมาขอรหัส?', 'รหัสกดเงินให้ใครไม่ได้เด็ดขาด เพราะเขาสามารถไปกดเงินสดที่ตู้ได้ทันที', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (219, 'medium', 'Deepfake คือเทคโนโลยีที่โจรเอามาใช้อย่างไร?', 'AI สามารถสร้างภาพเคลื่อนไหวและเสียงเลียนแบบบุคคลอื่นได้เนียนมาก', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (220, 'medium', 'วิธีเช็คว่าคนที่วิดีโอคอลมา เป็นตัวจริงหรือ Deepfake?', 'Deepfake มักจะมีจุดบกพร่องเมื่อมีการเคลื่อนไหวรวดเร็วผ่านใบหน้า', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (221, 'medium', '2FA (Two-Factor Authentication) คืออะไร?', 'เช่น ใส่รหัสผ่าน + รหัส OTP ช่วยป้องกันบัญชีได้ดีขึ้นมาก', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (222, 'medium', 'การอนุญาต Accessibility Service ใน Android เสี่ยงอย่างไร?', 'ฟีเจอร์ช่วยเหลือคนพิการ แต่มิจฉาชีพใช้ช่องโหว่นี้ในการรีโมทควบคุมเครื่องเหยื่อ', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (223, 'medium', 'Phishing Website มักจะมีลักษณะอย่างไร?', 'เช่น facbook.com (หายไปตัว e) หรือ kbank-secure.com (ชื่อยาวผิดปกติ)', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (224, 'medium', 'บัญชีม้า คืออะไร?', 'การรับจ้างเปิดบัญชีให้คนอื่น ผิดกฎหมายและมีโทษจำคุก', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (225, 'medium', 'Hybrid Scam คือกลโกงแบบไหน?', 'ผสมผสานระหว่าง Romance Scam (ความรัก) + Investment Scam (การลงทุน)', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (226, 'medium', 'Social Engineering (วิศวกรรมสังคม) คือ?', 'ไม่ได้แฮกที่ระบบ แต่แฮกที่ "คน" เช่น โทรมาหลอกให้ตกใจเพื่อขอรหัส', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (227, 'medium', 'ถ้าต้องการเช็คประวัติคนโกง ควรเช็คที่เว็บไหน?', 'เป็นเว็บฐานข้อมูลกลางที่คนมักจะมาแจ้งเตือนรายชื่อคนโกง', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (228, 'medium', 'PDPA เกี่ยวข้องกับอะไร?', 'Personal Data Protection Act กฎหมายที่ดูแลการเก็บและใช้ข้อมูลส่วนตัวของเรา', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (229, 'medium', 'การตั้งรหัสผ่านแบบไหน ปลอดภัยที่สุด?', 'ควรยาว มีตัวเลข ผสมสัญลักษณ์ และไม่เป็นคำที่มีในพจนานุกรม (Passphrase)', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (230, 'medium', 'Clickbait (คลิกเบต) อันตรายอย่างไร?', 'มักใช้คำกระตุ้นความอยากรู้อยากเห็น เพื่อล่อให้เข้าไปในเว็บที่ไม่ปลอดภัย', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (231, 'medium', 'Ransomware (มัลแวร์เรียกค่าไถ่) ทำงานอย่างไร?', 'จะเข้ารหัสไฟล์งานของเรา ทำให้เปิดไม่ได้ จนกว่าจะจ่ายเงินให้แฮกเกอร์', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (232, 'medium', 'ทำไมไม่ควรชาร์จมือถือกับตู้สาธารณะที่ไม่รู้จัก (Juice Jacking)?', 'พอร์ต USB สามารถส่งถ่ายข้อมูลได้ แฮกเกอร์อาจดัดแปลงตู้ชาร์จเพื่อขโมยข้อมูล', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (233, 'medium', 'Digital Footprint คืออะไร?', 'ทุกสิ่งที่เราโพสต์ คอมเมนต์ หรือเข้าชม จะถูกบันทึกไว้และอาจย้อนกลับมาทำร้ายเราได้', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (234, 'medium', 'Sextortion คือการข่มขู่แบบไหน?', 'มักเกิดจากการวิดีโอคอลเสียว หรือแฮกภาพส่วนตัวไปเรียกค่าไถ่', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (235, 'medium', 'Money Mule แปลว่าอะไร?', 'คนที่เป็นทางผ่านของเงินที่ได้มาอย่างผิดกฎหมาย', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (236, 'medium', 'ถ้าเจอข่าวปลอม (Fake News) ควรทำไง?', 'เช็คจากสำนักข่าวที่น่าเชื่อถือ หรือศูนย์ต่อต้านข่าวปลอม (Anti-Fake News Center)', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (237, 'medium', 'Vishing (Voice Phishing) คือ?', 'ใช้เสียง (Voice) โทรมาหลอกลวง เช่น แก๊งคอลเซ็นเตอร์', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (238, 'medium', 'Smishing คืออะไร?', 'SMS + Phishing = หลอกทางข้อความมือถือ', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (239, 'medium', 'Incognito Mode (โหมดไม่ระบุตัวตน) ช่วยอะไร?', 'ช่วยแค่ไม่ให้คนมาใช้คอมต่อเห็นประวัติเรา แต่ ISP และเว็บปลายทางยังเห็นเราอยู่', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (240, 'medium', 'Biometric Authentication คือ?', 'ใช้ลักษณะทางกายภาพระบุตัวตน ซึ่งปลอมแปลงยากกว่ารหัสผ่าน', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (241, 'hard', 'ซิมผี หรือ ซิมม้า คืออะไร?', 'ใช้เพื่อปกปิดตัวตนในการโทรหลอกลวง หรือรับ OTP เปิดบัญชีม้า', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (242, 'hard', 'ถ้ามี SMS แนบลิงก์ ชื่อผู้ส่งเป็นชื่อธนาคารเลย เชื่อได้ไหม?', 'SMS Sender Name สามารถปลอมแปลงได้ (Spoofing) อย่าเชื่อชื่อที่เห็น', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (243, 'hard', 'QR Code ดูดเงิน มีจริงไหม?', 'QR อาจพาไปเว็บ Phishing หลอกให้กรอกข้อมูล หรือดาวน์โหลดมัลแวร์', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (244, 'hard', 'การรับจ้างเปิดบัญชีม้า มีความผิดไหม?', 'ตาม พ.ร.ก. มาตรการป้องกันฯ อาชญากรรมทางเทคโนโลยี มีโทษหนักทั้งจำทั้งปรับ', 4);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (245, 'hard', 'กดลิงก์แล้วไม่ได้ทำอะไร เงินหายได้ไหม?', 'ลิงก์เป็นแค่ประตู แต่เงินจะหายเมื่อเราติดตั้งแอปโจร หรือกรอกรหัสให้เขา', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (246, 'hard', 'Clickbait (พาดหัวข่าวน่ากด) อันตรายยังไง?', 'มักใช้คำกระตุ้นความอยากรู้อยากเห็น เพื่อล่อเข้าไปเว็บที่มีอันตราย', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (247, 'hard', 'ทำไมโจรถึงชอบให้เราโอนแบบ Crypto (เหรียญดิจิทัล)?', 'ธุรกรรมคริปโตมีความเป็นส่วนตัวสูง ยากต่อการอายัดและติดตามเส้นทางเงิน', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (248, 'hard', 'การตั้งค่ามือถือ "ห้ามติดตั้งแอปจากแหล่งไม่รู้จัก" ช่วยอะไร?', 'เป็นการล็อคประตูบ้าน ไม่ให้โจรเอาแอปอันตรายมาติดตั้งในเครื่องเรา', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (249, 'hard', 'ถ้าคนร้ายรู้วันเกิดและเลขบัตรประชาชนเรา เขาเอาไปทำอะไรได้?', 'เป็นข้อมูลพื้นฐานที่ใช้ยืนยันตัวตน หรือเดารหัสผ่านได้ง่าย', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (250, 'hard', 'เว็บบน Google ที่ขึ้นคำว่า "Ad" หรือ "โฆษณา" เชื่อได้ไหม?', 'โจรยอมจ่ายเงินซื้อโฆษณาเพื่อให้เว็บปลอมของตัวเองขึ้นอันดับ 1 บน Google', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (251, 'hard', 'Zero-Day Exploit คืออะไร?', 'ช่องโหว่ที่ผู้พัฒนาเพิ่งรู้และยังแก้ไขไม่ทัน เป็นช่วงที่อันตรายที่สุด', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (252, 'hard', 'DDoS Attack คือการโจมตีแบบไหน?', 'Distributed Denial of Service การใช้คอมพิวเตอร์จำนวนมากถล่มเว็บให้ใช้งานไม่ได้', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (253, 'hard', 'VPN (Virtual Private Network) ช่วยเรื่องความปลอดภัยอย่างไร?', 'สร้างท่อข้อมูลส่วนตัวที่ปลอดภัย ป้องกันการดักจับข้อมูลระหว่างทาง', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (254, 'hard', 'End-to-End Encryption (E2EE) สำคัญอย่างไร?', 'แม้แต่ผู้ให้บริการ (เช่น LINE/WhatsApp) ก็อ่านข้อความเราไม่ได้', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (255, 'hard', 'Brute Force Attack คือ?', 'ใช้โปรแกรมลองผิดลองถูกรหัสผ่านเป็นล้านๆ ครั้งเพื่อเจาะระบบ', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (256, 'hard', 'Spyware มีหน้าที่หลักคือ?', 'สายลับที่ฝังตัวในเครื่องเพื่อขโมยรหัสผ่านหรือข้อมูลบัตรเครดิต', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (257, 'hard', 'Botnet คืออะไร?', 'เครื่องที่ติดมัลแวร์และถูกสั่งการพร้อมกันเพื่อโจมตีเป้าหมายอื่น', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (258, 'hard', 'SQL Injection เป็นการโจมตีที่ส่วนไหน?', 'การใส่โค้ดคำสั่งหลอกลวงเข้าไปในช่องกรอกข้อมูลเพื่อเจาะฐานข้อมูลเว็บ', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (259, 'hard', 'Man-in-the-Middle (MitM) Attack คือ?', 'แฮกเกอร์แทรกตัวอยู่ตรงกลางการสื่อสารเพื่อดักฟังหรือแก้ไขข้อมูล', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (260, 'hard', 'Cookie ในทางคอมพิวเตอร์คืออะไร?', 'ใช้จำการตั้งค่าหรือการล็อกอิน แต่ถ้าถูกขโมย (Session Hijacking) ก็อันตราย', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (261, 'hard', 'การทำ Sandboxing คืออะไร?', 'ทดสอบไฟล์ต้องสงสัยในกล่องปิดตาย ถ้าเป็นไวรัสก็จะไม่ลามออกมาข้างนอก', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (262, 'hard', 'Keylogger คือโปรแกรมประเภทไหน?', 'บันทึกทุกปุ่มที่เรากด เพื่อขโมยรหัสผ่านหรือข้อความแชท', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (263, 'hard', 'Rootkit อันตรายอย่างไร?', 'มัลแวร์ที่ฝังรากลึกและซ่อนตัวจากการตรวจจับของ Antivirus ทั่วไป', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (264, 'hard', 'Social Engineering แตกต่างจากการแฮกทั่วไปยังไง?', 'ใช้การหลอกลวง ตีสนิท หรือข่มขู่ ให้เหยื่อบอกรหัสผ่านเอง', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (265, 'hard', 'Whaling Phishing คือการโจมตีใคร?', 'การตกปลาตัวใหญ่ (Whale) เน้นหลอก CEO หรือ CFO เพื่อให้โอนเงินจำนวนมาก', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (266, 'hard', 'Trojan Horse (ม้าโทรจัน) ต่างจากไวรัสยังไง?', 'ต้องหลอกให้ผู้ใช้กดรันเอง โดยซ่อนมาในเกมเถื่อนหรือโปรแกรมแคร็ก', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (267, 'hard', 'Blockchain ช่วยเรื่องความปลอดภัยยังไง?', 'ความโปร่งใสและแก้ไขข้อมูลย้อนหลังไม่ได้ ทำให้ยากต่อการปลอมแปลงธุรกรรม', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (268, 'hard', 'SIM Swapping คือการโจมตีแบบไหน?', 'โจรขโมยเบอร์เราไปใส่เครื่องตัวเอง เพื่อรับ OTP แฮกบัญชีธนาคาร', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (269, 'hard', 'Honey Pot ในทาง Cyber Security คือ?', 'ระบบจำลองที่สร้างขึ้นเพื่อล่อให้แฮกเกอร์โจมตี เพื่อศึกษาพฤติกรรมหรือถ่วงเวลา', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (270, 'hard', 'Cross-Site Scripting (XSS) คือ?', 'ทำให้เว็บที่ดูปลอดภัยกลายเป็นตัวแพร่กระจายสคริปต์ขโมยข้อมูล', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (271, 'hard', 'Bluebugging คือการโจมตีผ่านช่องทางใด?', 'แฮกเกอร์เจาะเข้ามือถือผ่าน Bluetooth เพื่อดักฟังหรือขโมยข้อมูล', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (272, 'hard', 'White Hat Hacker คือใคร?', 'แฮกเกอร์สายขาว ที่เจาะระบบเพื่อหาช่องโหว่และแจ้งเจ้าของให้แก้ไข', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (273, 'hard', 'Black Hat Hacker ต่างจาก White Hat อย่างไร?', 'Black Hat เจาะระบบเพื่อขโมย ทำลาย หรือหาผลประโยชน์ใส่ตัว (ผิดกฎหมาย)', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (274, 'hard', 'Script Kiddie หมายถึงใครในวงการคอมฯ?', 'ผู้ที่ไม่มีความรู้ลึกซึ้ง แต่ใช้โปรแกรมสำเร็จรูปของคนอื่นมาแฮก', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (275, 'hard', 'CIA Triad ในความปลอดภัยสารสนเทศ ประกอบด้วย?', 'Confidentiality (ความลับ), Integrity (ความถูกต้อง), Availability (ความพร้อมใช้)', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (276, 'hard', 'HTTPS ต่างจาก HTTP ตรงที่มีการเพิ่มอะไร?', 'S ย่อมาจาก Secure (SSL/TLS) มีการเข้ารหัสข้อมูล', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (277, 'hard', 'Air Gap คือมาตรการความปลอดภัยแบบไหน?', 'การแยกคอมพิวเตอร์ออกจากเครือข่ายอินเทอร์เน็ตโดยสิ้นเชิง เพื่อป้องกันการแฮกจากภายนอก', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (278, 'hard', 'Steganography คือเทคนิคอะไร?', 'การอำพรางข้อมูลลับซ่อนไว้ในไฟล์อื่น เช่น ซ่อนข้อความในรูปภาพ', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (279, 'hard', 'Dictionary Attack คือการโจมตีรหัสผ่านแบบไหน?', 'ใช้บัญชีคำศัพท์ที่มีอยู่ในพจนานุกรมมาลองสุ่มเดารหัสผ่าน', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (280, 'hard', 'IoT (Internet of Things) มักมีจุดอ่อนเรื่องใด?', 'อุปกรณ์ IoT มักตั้งรหัสผ่านเดิมจากโรงงาน และไม่ค่อยได้รับการอัปเดตความปลอดภัย', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (281, 'hard', 'Evil Twin ในทาง Network คือ?', 'การปลอม Wi-Fi ให้ชื่อเหมือนของจริง เพื่อดักจับข้อมูลคนที่เผลอเชื่อมต่อ', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (282, 'hard', 'Firewall มีหน้าที่หลักคือ?', 'เปรียบเสมือนกำแพงที่คอยกรองข้อมูลเข้า-ออก ตามกฎความปลอดภัยที่ตั้งไว้', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (283, 'hard', 'การทำ Jailbreak หรือ Root เครื่อง มีความเสี่ยงคือ?', 'ทำให้ระบบป้องกันความปลอดภัยของ OS ถูกปิดลง แอปอันตรายเข้าถึงระบบลึกๆ ได้', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (284, 'hard', 'Shoulder Surfing คือพฤติกรรมแบบไหน?', 'การแอบมองข้ามไหล่เวลาคนอื่นกดรหัสหรือพิมพ์ข้อมูล', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (285, 'hard', 'Dumpster Diving ในทางความปลอดภัยคือ?', 'การค้นขยะเพื่อหาเอกสารสำคัญที่ทิ้งไม่ถูกวิธี เช่น ใบเสร็จ รหัสผ่าน', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (286, 'hard', 'Hash Function (เช่น MD5, SHA-256) ทำงานอย่างไร?', 'แปลงข้อมูลเป็นรหัสที่ไม่สามารถแปลงกลับเป็นข้อความเดิมได้ (One-way)', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (287, 'hard', 'Worm (หนอนคอมพิวเตอร์) ต่างจาก Virus ยังไง?', 'Worm แพร่กระจายผ่านเครือข่ายได้เองโดยไม่ต้องเกาะติดไฟล์อื่น', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (288, 'hard', 'Tailgating ในทางความปลอดภัยสถานที่คือ?', 'การเดินตามคนที่มีบัตรผ่านเข้าไปในพื้นที่หวงห้าม', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (289, 'hard', 'Logic Bomb คือมัลแวร์แบบไหน?', 'ฝังตัวเงียบๆ และจะทำงานเมื่อถึงเงื่อนไขที่กำหนด เช่น วันที่หรือเวลา', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (290, 'hard', 'Adware คือโปรแกรมประเภทใด?', 'โปรแกรมที่แสดงโฆษณารบกวนผู้ใช้ มักแฝงมากับโปรแกรมฟรี', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (291, 'hard', 'การโจมตีแบบ Water Hole Attack คือ?', 'แฮกเกอร์ฝังมัลแวร์ในเว็บที่เป้าหมายชอบเข้าใช้งานบ่อยๆ', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (292, 'hard', 'คำว่า "Patch" (แพตช์) ในทางคอมพิวเตอร์คือ?', 'ซอฟต์แวร์ขนาดเล็กที่ออกมาเพื่ออุดช่องโหว่หรือแก้บั๊ก', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (293, 'hard', 'Ping of Death คือการโจมตีแบบใด?', 'ส่งแพ็กเกจ Ping ขนาดใหญ่เกินปกติ ทำให้เครื่องเป้าหมายค้างหรือรีบูต', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (294, 'hard', 'Cookie Poisoning คือ?', 'การแก้ไขข้อมูลใน Cookie เพื่อปลอมแปลงสถานะหรือสิทธิ์ของผู้ใช้', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (295, 'hard', 'Tor Browser มักใช้เพื่อเข้าถึงอะไร?', 'ใช้เข้าถึง Dark Web และปกปิดตัวตนผู้ใช้งาน (The Onion Router)', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (296, 'hard', 'Scareware มีลักษณะอย่างไร?', 'แจ้งเตือนปลอมๆ ว่าเครื่องมีไวรัส เพื่อหลอกให้ซื้อโปรแกรมแก้', 2);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (297, 'hard', 'การเข้ารหัสแบบ Symmetric Key คือ?', 'ใช้กุญแจดอกเดียวกัน ทั้งในการล็อก (Encrypt) และปลดล็อก (Decrypt)', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (298, 'hard', 'การเข้ารหัสแบบ Asymmetric Key (Public/Private) คือ?', 'ใช้กุญแจคู่: สาธารณะสำหรับล็อก และส่วนตัวสำหรับปลดล็อก', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (299, 'hard', 'การ "Salt" รหัสผ่าน คือ?', 'เติมค่าสุ่มลงไปในรหัสผ่านก่อนเข้ารหัส เพื่อกันการเดาด้วย Rainbow Table', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (300, 'hard', 'VPN ย่อมาจากอะไร?', 'Virtual Private Network เครือข่ายส่วนตัวเสมือน', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (301, 'hard', 'SQL ย่อมาจาก?', 'Structured Query Language ภาษามาตรฐานในการจัดการฐานข้อมูล', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (302, 'hard', 'Port 443 ปกติใช้สำหรับอะไร?', 'เป็นพอร์ตมาตรฐานของ HTTPS (Web secure)', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (303, 'hard', 'Port 80 ปกติใช้สำหรับอะไร?', 'เป็นพอร์ตมาตรฐานของ HTTP (Web ธรรมดา)', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (304, 'hard', 'การโจมตีแบบ Spoofing คือ?', 'การปลอมแปลงตัวตน เช่น ปลอม IP, ปลอมอีเมล, ปลอมเบอร์โทร', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (305, 'hard', 'Polymorphic Virus คือ?', 'ไวรัสที่เปลี่ยนโครงสร้างตัวเองได้เรื่อยๆ เพื่อหลบ Antivirus', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (306, 'hard', 'Bio-hacking คือ?', 'การดัดแปลงชีวภาพหรือฝังชิปในร่างกายเพื่อเชื่อมต่อกับคอมพิวเตอร์', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (307, 'hard', 'Deep Web ต่างจาก Dark Web ไหม?', 'Deep Web คือส่วนที่ Google เข้าไม่ถึง (เช่น อีเมล) แต่ Dark Web ต้องใช้โปรแกรมเฉพาะและมักมีสิ่งผิดกฎหมาย', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (308, 'hard', 'Penetration Testing (Pen Test) คือ?', 'การจ้างผู้เชี่ยวชาญมาจำลองการเจาะระบบเพื่อหาช่องโหว่', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (309, 'hard', 'ข้อมูล Metadata ของรูปถ่าย บอกอะไรได้บ้าง?', 'บอกรุ่นกล้อง, วันเวลา, และพิกัด GPS ที่ถ่ายรูปนั้น', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (310, 'hard', 'การโจมตีแบบ Sniffing คือ?', 'การใช้โปรแกรมดักจับแพ็กเก็ตข้อมูลที่วิ่งอยู่ในเครือข่าย', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (311, 'hard', 'Captcha มีไว้เพื่อ?', 'Completely Automated Public Turing test to tell Computers and Humans Apart (แยกคนออกจากบอท)', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (312, 'hard', 'Bloatware คือ?', 'โปรแกรมขยะที่แถมมากับเครื่อง ไม่จำเป็นและทำให้เครื่องช้า', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (313, 'hard', 'IP Address เปรียบเหมือนอะไร?', 'เลขที่อยู่ของอุปกรณ์ในเครือข่ายอินเทอร์เน็ต', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (314, 'hard', 'การโจมตีแบบ Pharming คือ?', 'การเปลี่ยนเส้นทาง (Redirect) จากเว็บจริงไปยังเว็บปลอมโดยที่ผู้ใช้ไม่รู้ตัว', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (315, 'hard', 'MAC Address เปลี่ยนแปลงได้ง่ายไหม?', 'เป็นเลขประจำตัวฮาร์ดแวร์การ์ดแลน ปกติจะเปลี่ยนไม่ได้ (แต่ปลอมแปลงได้)', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (316, 'hard', 'HTTPS ใช้พอร์ตอะไรเป็นหลัก?', '443', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (317, 'hard', 'SSH (Secure Shell) ใช้ทำอะไร?', 'ใช้รีโมทเข้าไปควบคุมคอมพิวเตอร์ผ่านเครือข่ายอย่างปลอดภัย', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (318, 'hard', 'Default Gateway คือ?', 'ประตูทางออกของเครือข่าย (มักเป็น IP ของ Router)', 1);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (319, 'hard', 'Bug Bounty Program คือ?', 'โครงการที่บริษัทจ่ายเงินรางวัลให้แฮกเกอร์ที่เจอช่องโหว่', 3);
INSERT INTO public.questions (qid, level, question, explanation, cg_id) VALUES (320, 'hard', 'Session Hijacking คือ?', 'การขโมย Session ID เพื่อสวมรอยเป็นผู้ใช้คนนั้นโดยไม่ต้องรู้รหัสผ่าน', 3);
