INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (1, 'callcenter-1', 'callcenter', '📞 แก๊งคอลเซ็นเตอร์ & แอบอ้าง', 1, 'ไปรษณีย์ไทย (ฝ่ายตรวจสอบ)', '📦', 'money', '{"msgs": ["สวัสดีครับ แจ้งจากไปรษณีย์ไทย", "พัสดุหมายเลข TH998877 ของคุณถูกตีกลับจากศุลกากร", "เนื่องจากสแกนพบ ''พาสปอร์ตปลอม 15 เล่ม'' ภายในกล่องครับ"], "choices": [{"next": {"id": "callcenter-1-sub1", "msgs": ["ตอนนี้ทางเราได้ประสานงานกับ สภ.เมืองเชียงใหม่ แล้ว", "คุณสะดวกเดินทางไปให้ปากคำที่เชียงใหม่ภายใน 2 ชั่วโมงไหมครับ?"], "name": "ไปรษณีย์ไทย", "level": 1, "avatar": "📦", "choices": [{"next": {"id": "callcenter-1-sub2", "msgs": ["(เสียงวิทยุสื่อสารแทรก) สวัสดีครับ ผู้กองสมชายรับสาย", "เพื่อพิสูจน์ความบริสุทธิ์ คุณต้องโอนเงินในบัญชีมาให้กองปราบตรวจสอบ", "ใช้เวลา 15 นาที ถ้าไม่ผิดเดี๋ยวโอนคืนให้ครับ"], "name": "สภ.เมืองเชียงใหม่", "level": 1, "avatar": "👮‍♂️", "choices": [{"text": "A: ได้ครับ โอนไปที่บัญชีไหนครับ?", "memeDesc": "ตำรวจจริงไม่มีนโยบายให้โอนเงินตรวจสอบ!", "memeIcon": "💸", "reaction": "โอนเข้าบัญชีกลาง นายสมปอง ครับ", "isCorrect": false, "memeTitle": "SAD..."}, {"text": "B: ตำรวจบ้าอะไรให้โอนเงิน แจ้งความท้องที่ผมดีกว่า", "memeDesc": "มีสติ ไม่ตื่นตระหนก รอดไปได้!", "memeIcon": "🛡️", "reaction": "เดี๋ยวผมจะออกหมายจับคุณ! (ตัดสาย)", "isCorrect": true, "memeTitle": "NICE SAVE"}], "category": "callcenter", "categoryTitle": ""}, "text": "A: ไปไม่ได้ครับ อยู่ไกลมากทำไงดี?", "reaction": "งั้นเดี๋ยวผมโอนสายให้ ''ผู้กองสมชาย'' รับแจ้งความออนไลน์นะครับ"}, {"text": "B: สะดวกครับ เดี๋ยวเจอกันที่โรงพักเชียงใหม่เลย", "memeDesc": "เล่นมุกนี้ โจรไปไม่เป็นเลยทีเดียว!", "memeIcon": "😏", "reaction": "เอ่อ... (รีบตัดสายทิ้ง)", "isCorrect": true, "memeTitle": "CALL BLUFF"}], "category": "callcenter", "categoryTitle": ""}, "text": "A: ตกใจ! ไม่เคยส่งพาสปอร์ตนะ", "reaction": "พัสดุระบุชื่อและเบอร์โทรของคุณชัดเจนครับ"}, {"next": {"id": "callcenter-1-sub3", "msgs": ["ถ้าคุณยืนยันว่าไม่ได้ส่ง คุณต้องโอนค่าธรรมเนียมยกเลิกพัสดุ 1,500 บาท", "ไม่งั้นจะมีความผิดทางกฎหมายครับ"], "name": "ไปรษณีย์ไทย", "level": 1, "avatar": "📦", "choices": [{"text": "A: โอนก็ได้ครับ จะได้จบๆ ไป", "memeDesc": "ตัดรำคาญด้วยการโอนเงิน = เสร็จโจร", "memeIcon": "🤦", "reaction": "รอรับสลิปนะครับ (บล็อก)", "isCorrect": false, "memeTitle": "EASY PREY"}, {"text": "B: งั้นทิ้งไปเลยครับ ยกให้", "memeDesc": "ไม่แคร์ ไม่สน โจรก็ทำอะไรไม่ได้", "memeIcon": "🗿", "reaction": "ไม่ได้ครับ มันผิดกฎหมาย! ฮัลโหล! (ตู๊ดๆ)", "isCorrect": true, "memeTitle": "DON''T CARE"}], "category": "callcenter", "categoryTitle": ""}, "text": "B: ส่งผิดรึเปล่าครับ ผมสั่งแต่เสื้อผ้า", "reaction": "แต่ชื่อผู้ส่งเป็นชื่อคุณนะครับ"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (2, 'callcenter-2', 'callcenter', '📞 แก๊งคอลเซ็นเตอร์ & แอบอ้าง', 2, 'กสทช. (ฝ่ายระงับสัญญาณ)', '📡', 'data', '{"msgs": ["ประกาศจาก กสทช. เบอร์มือถือของคุณมีประวัติส่งข้อความหลอกลวง 5,000 ครั้ง", "สัญญาณของคุณจะถูกระงับภายใน 1 ชั่วโมง", "หากต้องการตรวจสอบ กรุณากด 9"], "choices": [{"next": {"id": "callcenter-2-sub1", "msgs": ["เราจำเป็นต้องตรวจสอบข้อมูลทะเบียนราษฎร์ของคุณ", "กรุณาแอดไลน์ไอดี @NBTC-Police เพื่อส่งรูปบัตรประชาชนหน้า-หลัง"], "name": "เจ้าหน้าที่ กสทช.", "level": 2, "avatar": "👨‍💼", "choices": [{"text": "A: แอดไลน์ไปแล้วครับ ต้องถ่ายรูปคู่บัตรไหม?", "memeDesc": "ส่งรูปบัตรให้คนแปลกหน้า = หายนะ!", "memeIcon": "🪪", "reaction": "ถ่ายมาให้ชัดเจนนะครับ (โดนเอาข้อมูลไปกู้เงิน)", "isCorrect": false, "memeTitle": "IDENTITY THEFT"}, {"text": "B: หน่วยงานรัฐใช้ LINE @ ธรรมดาหรอครับ?", "memeDesc": "หน่วยงานรัฐไม่ให้แอดไลน์คุยเรื่องบัตร ปชช. หรอกนะ", "memeIcon": "👀", "reaction": "เป็นไลน์พิเศษสำหรับคดีด่วนครับ! (แถ)", "isCorrect": true, "memeTitle": "SHARP EYE"}], "category": "callcenter", "categoryTitle": ""}, "text": "A: (กด 9) ติดต่อเจ้าหน้าที่", "reaction": "สวัสดีครับ กสทช. รับสายครับ เบอร์คุณไปผูกกับบัญชีม้าครับ"}, {"next": {"id": "callcenter-2-sub2", "msgs": ["ถ้าไม่ให้ความร่วมมือ จะส่งตำรวจไปจับที่บ้านเดี๋ยวนี้"], "name": "กสทช.", "level": 2, "avatar": "📡", "choices": [{"text": "A: ยอมแล้วครับ ต้องทำไงบอกมาเลย", "memeDesc": "โดนขู่คำเดียว สติหลุดเลย!", "memeIcon": "😱", "reaction": "โอนเงินมาประกันตัว 5,000 บาทครับ", "isCorrect": false, "memeTitle": "PANIC MODE"}, {"text": "B: มาเลยครับ ซื้อหมูปิ้งมารอแล้ว", "memeDesc": "หิวหมูปิ้งมากกว่ากลัวโดนจับ!", "memeIcon": "🍢", "reaction": "ไอ้... (ด่าพ่อแล้วตัดสาย)", "isCorrect": true, "memeTitle": "HUNGRY TROLL"}], "category": "callcenter", "categoryTitle": ""}, "text": "B: ระงับไปเลยครับ ใช้เบอร์อื่นอยู่", "reaction": "ทางเราจะดำเนินคดีตามกฎหมายสูงสุดนะครับ!"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (3, 'callcenter-3', 'callcenter', '📞 แก๊งคอลเซ็นเตอร์ & แอบอ้าง', 3, 'ศูนย์บัตรเครดิต K-Bank', '💳', 'money', '{"msgs": ["สวัสดีค่ะ แจ้งเตือนยอดรูดบัตรเครดิตผิดปกติ", "มีการรูดซื้อทองคำมูลค่า 50,000 บาท ที่ห้างในภูเก็ต", "หากคุณไม่ได้ทำรายการ กรุณายืนยันเพื่อยกเลิก"], "choices": [{"next": {"id": "callcenter-3-sub1", "msgs": ["ขอบคุณค่ะ ต่อไปขอตัวเลข CVV 3 ตัวหลังบัตร", "และรหัส OTP ที่กำลังจะส่งไปที่มือถือคุณค่ะ"], "name": "เจ้าหน้าที่บัตร", "level": 3, "avatar": "👩‍💼", "choices": [{"text": "A: ได้ค่ะ รหัส OTP คือ 884521", "memeDesc": "ห้ามบอกรหัส OTP กับใครเด็ดขาด!", "memeIcon": "🔥", "reaction": "ขอบคุณที่ให้รหัสนะคะ (บัตรโดนรูดจริงทันที)", "isCorrect": false, "memeTitle": "OTP = OH TERRIBLE PROBLEM"}, {"text": "B: เจ้าหน้าที่ธนาคารทำไมไม่รู้เลขบัตรลูกค้าล่ะ?", "memeDesc": "ตรรกะง่ายๆ แต่ทำมิจฉาชีพไปไม่เป็น!", "memeIcon": "🧠", "reaction": "ระบบเราโดนล็อกค่ะ เลยต้องถามเพื่อยืนยัน (แถสุดๆ)", "isCorrect": true, "memeTitle": "LOGIC WIN"}], "category": "callcenter", "categoryTitle": ""}, "text": "A: ไม่ได้รูดเลยค่ะ! ยกเลิกด่วน", "reaction": "เพื่อการยกเลิก รบกวนแจ้งหมายเลขหน้าบัตร 16 หลักค่ะ"}, {"next": {"id": "callcenter-3-sub2", "msgs": ["ถ้าใช่ รบกวนโอนค่าธรรมเนียมรูดบัตรข้ามจังหวัด 500 บาทด้วยค่ะ"], "name": "เจ้าหน้าที่บัตร", "level": 3, "avatar": "👩‍💼", "choices": [{"text": "A: โอนก็โอนค่ะ (ยอมจ่าย 500)", "memeDesc": "รวยทิพย์ โดนหลอกจริง!", "memeIcon": "💸", "reaction": "เรียบร้อยค่ะ (กินเงินฟรี)", "isCorrect": false, "memeTitle": "FLEX GONE WRONG"}, {"text": "B: ผมไม่มีบัตรเครดิตธนาคารนี้ครับ", "memeDesc": "ไม่มีบัตร ก็ไม่มีหนี้ให้แฮก!", "memeIcon": "🙅", "reaction": "อ้าว หรอคะ... (ตื๊ดๆๆ)", "isCorrect": true, "memeTitle": "NO CARD NO PROBLEM"}], "category": "callcenter", "categoryTitle": ""}, "text": "B: รูดเองแหละค่ะ รวยจัด", "reaction": "เอ่อ... คุณลูกค้าแน่ใจนะคะว่ารูดซื้อทอง?"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (4, 'callcenter-4', 'callcenter', '📞 แก๊งคอลเซ็นเตอร์ & แอบอ้าง', 4, 'การไฟฟ้านครหลวง (ฝ่ายบัญชี)', '⚡', 'money', '{"msgs": ["สวัสดีครับ คุณค้างชำระค่าไฟ 3 เดือน ยอด 4,500 บาท", "เจ้าหน้าที่จะเข้าไปตัดมิเตอร์ไฟที่บ้านภายใน 1 ชั่วโมงครับ", "จะชำระตอนนี้เพื่อเลื่อนการตัดไฟไหมครับ?"], "choices": [{"next": {"id": "callcenter-4-sub1", "msgs": ["ระบบสร้าง QR Code ไม่ได้ครับ", "รบกวนโหลดแอป MEA (ไฟล์ APK) จากลิงก์นี้เพื่อกดชำระเงินแทนครับ"], "name": "แอดมิน กฟน.", "level": 4, "avatar": "📱", "choices": [{"text": "A: โหลดแล้วครับ กำลังกดเข้าแอป", "memeDesc": "โหลดแอปเถื่อน โดนรีโมทควบคุมมือถือ!", "memeIcon": "📱", "reaction": "(มือถือจอดำ โดนดูดเงินหมดบัญชี)", "isCorrect": false, "memeTitle": "REMOTE HACKED"}, {"text": "B: ขอไปจ่ายที่ 7-11 หน้าปากซอยดีกว่า", "memeDesc": "เดินไปจ่ายเอง ปลอดภัยกว่าโหลดลิงก์มั่ว!", "memeIcon": "🚶‍♂️", "reaction": "ไม่ได้ครับ ต้องจ่ายผ่านแอปเราเท่านั้น!", "isCorrect": true, "memeTitle": "SAFE WALK"}], "category": "callcenter", "categoryTitle": ""}, "text": "A: อ้าว ลืมจ่ายหรอ! จ่ายตอนนี้เลยครับ", "reaction": "ดีครับ แอดไลน์การไฟฟ้ามาที่ @MEA-Help เพื่อรับคิวอาร์โค้ด"}, {"next": {"id": "callcenter-4-sub2", "msgs": ["ถ้าช่างไปถึงหน้าบ้าน จะเสียค่าต่อไฟใหม่ 2,000 บาทนะ จ่ายครึ่งเดียวก่อนไหม?"], "name": "ช่างไฟจำแลง", "level": 4, "avatar": "🛠️", "choices": [{"text": "A: งั้นโอนครึ่งนึงก่อนก็ได้ หยวนๆ", "memeDesc": "จะครึ่งเดียวหรือเต็มจำนวน ก็โดนหลอกอยู่ดี", "memeIcon": "📉", "reaction": "ดีมากครับน้อง (หวานเจี๊ยบ)", "isCorrect": false, "memeTitle": "HALF SCAMMED"}, {"text": "B: ผมจุดเทียนอยู่ครับ โรแมนติกดี", "memeDesc": "สุนทรีย์เกินไป โจรรับมือไม่ไหว!", "memeIcon": "🕯️", "reaction": "...ไอ้บ้าเอ้ย (วางสาย)", "isCorrect": true, "memeTitle": "ROMANTIC VIBES"}], "category": "callcenter", "categoryTitle": ""}, "text": "B: ตัดเลยครับ ช่วงนี้อากาศหนาว", "reaction": "คุณจะไม่มีไฟฟ้าใช้นะครับ! โทรศัพท์ก็จะชาร์จไม่ได้!"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (5, 'callcenter-5', 'callcenter', '📞 แก๊งคอลเซ็นเตอร์ & แอบอ้าง', 5, 'กรมสอบสวนคดีพิเศษ (DSI)', '🕵️‍♂️', 'data', '{"msgs": ["ผมพันตำรวจโท... แจ้งจาก DSI", "เราจับกุม ''เสี่ยโป้'' ได้ และพบสมุดบัญชีชื่อคุณในตู้เซฟ", "คุณถูกซัดทอดว่ารับจ้างเปิดบัญชีม้าครับ"], "choices": [{"next": {"id": "callcenter-5-sub1", "msgs": ["เราจะทำการบันทึกเสียงและวิดีโอคอลเพื่อสอบปากคำ", "รบกวนมองกล้องและอ่านข้อความตามที่ผมบอก เพื่อบันทึกไบโอเมตริกใบหน้า"], "name": "ผู้บัญชาการ DSI", "level": 5, "avatar": "👮", "choices": [{"text": "A: (มองกล้อง สแกนหน้า พยักหน้าตามคำสั่ง)", "memeDesc": "โดนหลอกสแกนหน้าเอาไปทำธุรกรรมเรียบร้อย!", "memeIcon": "📸", "reaction": "บันทึกใบหน้าสำเร็จ (เอาไปปลดล็อกแอปธนาคาร)", "isCorrect": false, "memeTitle": "FACE SCANNED"}, {"text": "B: ไม่คอลครับ จะสอบปากคำก็ส่งหมายเรียกมา", "memeDesc": "รู้กฎหมาย หมายเรียกต้องเป็นกระดาษเท่านั้น!", "memeIcon": "📄", "reaction": "ถ้าไม่ร่วมมือเราจะบุกไปค้นบ้านเดี๋ยวนี้!", "isCorrect": true, "memeTitle": "LAW EXPERT"}], "category": "callcenter", "categoryTitle": ""}, "text": "A: บัญชีม้าอะไร ไม่เคยรู้จักเสี่ยโป้นะ!", "reaction": "อย่าเพิ่งปฏิเสธครับ เรามีหลักฐาน"}, {"next": {"id": "callcenter-5-sub2", "msgs": ["โทษจำคุก 10 ปี ปรับ 1 ล้านบาท โอนมาเคลียร์ใต้โต๊ะซะดีๆ 5,000 พอ"], "name": "DSI (เสียงโมโห)", "level": 5, "avatar": "😠", "choices": [{"text": "A: 5,000 ก็ได้ครับ ถูกกว่าติดคุก", "memeDesc": "คิดจะติดสินบนตำรวจ เจอโจรตัวจริงซะงั้น!", "memeIcon": "🤝", "reaction": "ขอบคุณครับ ยินดีที่ได้ทำธุรกิจ", "isCorrect": false, "memeTitle": "BRIBE GONE WRONG"}, {"text": "B: DSI ที่ไหนรับเงินใต้โต๊ะผ่านแชท", "memeDesc": "โจรโมโหที่หลอกเราไม่ได้!", "memeIcon": "😂", "reaction": "เก่งนักนะมึง! (วางสาย)", "isCorrect": true, "memeTitle": "UNBREAKABLE"}], "category": "callcenter", "categoryTitle": ""}, "text": "B: ดีเลยครับ กำลังอยากเข้าคุกไปหาเพื่อน", "reaction": "คุณคิดว่าเรื่องนี้เป็นเรื่องล้อเล่นหรอครับ?"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (6, 'callcenter-6', 'callcenter', '📞 แก๊งคอลเซ็นเตอร์ & แอบอ้าง', 6, 'กรมที่ดิน (ฝ่ายภาษี)', '🏡', 'data', '{"msgs": ["สวัสดีครับ ติดต่อจากกรมที่ดิน", "รัฐบาลมีนโยบายคืนเงินภาษีที่ดินประจำปี 2,500 บาท", "คุณยังมีสิทธิ์รับเงินอยู่นะครับ"], "choices": [{"next": {"id": "callcenter-6-sub1", "msgs": ["พอโหลดเสร็จ ให้เข้าไปตั้งรหัส PIN 6 หลัก", "(แนะนำให้ใช้รหัสเดียวกับแอปธนาคาร เพื่อความจำง่ายนะครับ)"], "name": "กรมที่ดิน", "level": 6, "avatar": "📱", "choices": [{"text": "A: โหลดแล้ว ตั้งรหัสเดิมเลย จะได้ไม่ลืม", "memeDesc": "ให้รหัส PIN ไปง่ายๆ เงินก็ไปง่ายๆ เช่นกัน", "memeIcon": "🔢", "reaction": "(โดนดูดรหัส PIN เอาไปปลดล็อกแอปธนาคาร)", "isCorrect": false, "memeTitle": "PIN COMPROMISED"}, {"text": "B: จะคืนเงินก็โอนเข้าพร้อมเพย์สิ โหลดแอปทำไม?", "memeDesc": "แค่ถามหาเหตุผล โจรก็จนตรอก", "memeIcon": "🤔", "reaction": "ขั้นตอนใหม่ของรัฐบาลครับ! (พยายามแถ)", "isCorrect": true, "memeTitle": "LOGICAL THINKING"}], "category": "callcenter", "categoryTitle": ""}, "text": "A: ดีจังเลย ต้องทำยังไงบ้างคะ?", "reaction": "รบกวนติดตั้งแอป ''Smart Land'' เพื่อยืนยันรับสิทธิ์ครับ"}, {"next": {"id": "callcenter-6-sub2", "msgs": ["แค่บอกเลขบัตรประชาชนมา เดี๋ยวพี่ลงทะเบียนให้"], "name": "กรมที่ดิน... เอ้ย คนละครึ่ง", "level": 6, "avatar": "😅", "choices": [{"text": "A: เอาครับ เลข 1100...", "memeDesc": "เปลี่ยนมุกหลอก ก็ยังอุตส่าห์ไปเชื่อมันอีก!", "memeIcon": "🤦‍♂️", "reaction": "เสร็จโจร!", "isCorrect": false, "memeTitle": "GULLIBLE"}, {"text": "B: กรมที่ดินแจกคนละครึ่งตั้งแต่เมื่อไหร่ มั่วละ", "memeDesc": "มุกมั่วซั่วแบบนี้ หลอกคนมีสติไม่ได้หรอก!", "memeIcon": "🚫", "reaction": "ฝากไว้ก่อนเถอะ! (วางสาย)", "isCorrect": true, "memeTitle": "CAUGHT RED-HANDED"}], "category": "callcenter", "categoryTitle": ""}, "text": "B: ผมเช่าบ้านเขาอยู่ครับ ไม่มีที่ดิน", "reaction": "งั้นเปลี่ยนเป็นรับสิทธิ์คนละครึ่งแทนไหมครับ?"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (7, 'callcenter-7', 'callcenter', '📞 แก๊งคอลเซ็นเตอร์ & แอบอ้าง', 7, 'กรมสรรพากร (RD)', '📊', 'money', '{"msgs": ["สวัสดีครับ เราพบว่าปีนี้คุณมีรายได้เข้าบัญชีเกิน 2 ล้านบาท", "แต่ยังไม่ได้ยื่นแบบภาษี ภ.ง.ด. 90", "กรุณาชำระภาษีย้อนหลังด่วนเพื่อหลีกเลี่ยงค่าปรับ"], "choices": [{"next": {"id": "callcenter-7-sub1", "msgs": ["เพื่ออายัดเงินส่วนนั้น คุณต้องโอนเงินค่ามัดจำศาล 5,000 บาท", "โอนเข้าบัญชีส่วนตัวของหัวหน้าแผนกก่อนได้เลยครับ"], "name": "กรมสรรพากร", "level": 7, "avatar": "📊", "choices": [{"text": "A: โอนไปแล้วค่ะ ช่วยเคลียร์ให้หนูด้วยนะ", "memeDesc": "สรรพากรไม่มีบัญชีส่วนตัวให้โอนหรอกนะ!", "memeIcon": "💨", "reaction": "ขอบคุณครับน้อง (หายไปกับสายลม)", "isCorrect": false, "memeTitle": "MONEY GONE"}, {"text": "B: บัญชีส่วนตัวหัวหน้า? สรรพากรทำงานแบบนี้หรอ?", "memeDesc": "โอนเงินราชการต้องเป็นชื่อหน่วยงานเท่านั้น!", "memeIcon": "🏛️", "reaction": "เอ่อ... เป็นมาตรการเร่งด่วนครับ", "isCorrect": true, "memeTitle": "COMMON SENSE"}], "category": "callcenter", "categoryTitle": ""}, "text": "A: ตกใจ! ปีนี้หนูเพิ่งทำงานได้เดือนเดียวเองนะคะ", "reaction": "อาจจะมีคนแอบอ้างใช้บัญชีคุณรับเงินสีเทาครับ"}, {"next": {"id": "callcenter-7-sub2", "msgs": ["ถ้าไม่โอนภาษีมาตอนนี้ ผมจะสั่งอายัดทุกบัญชีของคุณ!"], "name": "สรรพากร (เริ่มหงุดหงิด)", "level": 7, "avatar": "😤", "choices": [{"text": "A: อย่านะครับ ยอมแล้วๆ โอนเลย", "memeDesc": "โดนขู่นิดเดียวก็ยอมเสียเงินฟรีซะแล้ว", "memeIcon": "😿", "reaction": "ฮ่าๆ ง่ายจังวะ", "isCorrect": false, "memeTitle": "SCAREDY CAT"}, {"text": "B: ตอนนี้มีอยู่ 20 บาท อายัดไปเลยพี่", "memeDesc": "มีแค่ 20 บาท โจรยังต้องร้องไห้", "memeIcon": "🪙", "reaction": "โถ่เอ้ย เสียเวลาคุย! (ตัดสาย)", "isCorrect": true, "memeTitle": "EMPTY WALLET"}], "category": "callcenter", "categoryTitle": ""}, "text": "B: สาธุ! ขอให้มีเงินเข้า 2 ล้านจริงๆ เถอะ", "reaction": "นี่ไม่ใช่เรื่องล้อเล่นนะครับ จะให้ส่งหมายศาลไปไหม?"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (8, 'callcenter-8', 'callcenter', '📞 แก๊งคอลเซ็นเตอร์ & แอบอ้าง', 8, 'Thai Smile Airways (ฝ่ายโปรโมชั่น)', '✈️', 'data', '{"msgs": ["สวัสดีค่ะ ยินดีด้วย! เบอร์ของคุณได้รับเลือกเป็นผู้โชคดี", "รับตั๋วเครื่องบินไป-กลับ ญี่ปุ่น ฟรี 2 ที่นั่ง!", "เงื่อนไขคือต้องลงทะเบียนรับสิทธิ์ภายใน 10 นาทีนี้ค่ะ"], "choices": [{"next": {"id": "callcenter-8-sub1", "msgs": ["ทางเราขอเก็บ ''ค่าภาษีสนามบิน'' ก่อนนะคะ จำนวน 3,500 บาท", "พอไปถึงสนามบินแล้ว จะคืนเป็นเงินสดให้ค่ะ"], "name": "แอดมินสายการบิน", "level": 8, "avatar": "👩‍✈️", "choices": [{"text": "A: แค่ 3,500 แลกกับตั๋วฟรี คุ้ม! โอนค่ะ", "memeDesc": "ค่าภาษีสนามบินล่วงหน้า? โดนหลอกแล้ว!", "memeIcon": "🛬", "reaction": "ตั๋วทิพย์บินตรงสู่ความว่างเปล่า~", "isCorrect": false, "memeTitle": "FLY TO NOWHERE"}, {"text": "B: ไหนบอกว่าฟรีทุกอย่างไง ทำไมต้องจ่ายเพิ่ม?", "memeDesc": "ของฟรีมักมีเงื่อนไข (แอบแฝง) เสมอ", "memeIcon": "🔍", "reaction": "เป็นกฎกติกาค่ะ... (แถไม่ออก)", "isCorrect": true, "memeTitle": "READ THE FINE PRINT"}], "category": "callcenter", "categoryTitle": ""}, "text": "A: กรี๊ดดด! อยากไปญี่ปุ่นพอดี ต้องทำไงคะ?", "reaction": "รบกวนแอดไลน์ @JapanFreeTrip เพื่อกรอกข้อมูลพาสปอร์ตค่ะ"}, {"next": {"id": "callcenter-8-sub2", "msgs": ["ถ้าไม่รับสิทธิ์ จะโอนให้ผู้โชคดีท่านอื่นเลยนะคะ!"], "name": "แอดมิน (เริ่มล่ก)", "level": 8, "avatar": "💦", "choices": [{"text": "A: เอ้ย รับสิทธิ์ๆ เดี๋ยวกดลิงก์ให้", "memeDesc": "กลัวพลาดของดี จนลืมเช็คความจริง!", "memeIcon": "🏃‍♂️", "reaction": "(โดนสแปมไวรัสลงมือถือ)", "isCorrect": false, "memeTitle": "FOMO"}, {"text": "B: โอนให้คนอื่นเลยจ้า ตามสบาย", "memeDesc": "ไม่โลภ ก็ไม่โดนหลอก", "memeIcon": "🍷", "reaction": "ชิ! รู้มากนักนะ (วางสาย)", "isCorrect": true, "memeTitle": "GIGA CHAD"}], "category": "callcenter", "categoryTitle": ""}, "text": "B: สายการบินนี้เขาเลิกบินไปแล้วไม่ใช่หรอ?", "reaction": "เอ่อ... เราเป็นสายการบินเปิดใหม่ ชื่อคล้ายกันค่ะ"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (9, 'callcenter-9', 'callcenter', '📞 แก๊งคอลเซ็นเตอร์ & แอบอ้าง', 9, 'สมพร (เพื่อนสมัยประถม)', '👦', 'money', '{"msgs": ["เห้ยมึง สบายดีป่าววะ ไม่ได้คุยกันนานเลย", "จำกูได้ป่าว สมพรไง ที่เคยเตะบอลด้วยกัน", "พอดียายกูเข้าโรงบาล กูช็อตหนักมาก ขอยืมสัก 3,000 ได้ไหม"], "choices": [{"next": {"id": "callcenter-9-sub1", "msgs": ["โอนแล้วส่งสลิปมานะ เดี๋ยวเดือนหน้ากูรีบคืนให้พร้อมดอกเลย"], "name": "สมพร (เพื่อนรัก)", "level": 9, "avatar": "👦", "choices": [{"text": "A: โอนละเพื่อน สู้ๆ นะเว้ย", "memeDesc": "เพื่อนก็ปลอม บัญชีก็ม้า!", "memeIcon": "🔪", "reaction": "ขอบใจมากโง่จังเพื่อนรัก (บล็อก)", "isCorrect": false, "memeTitle": "BETRAYED"}, {"text": "B: เดี๋ยวๆ ทำไมชื่อบัญชีผู้หญิง? ขอวิดีโอคอลหน่อยดิ", "memeDesc": "เช็คให้ชัวร์ก่อนโอนให้เพื่อน (ที่ไม่ได้เจอนาน)", "memeIcon": "🕵️", "reaction": "กูอยู่ไอซียู หมอไม่ให้ใช้เสียง (แถ)", "isCorrect": true, "memeTitle": "TRUST ISSUES"}], "category": "callcenter", "categoryTitle": ""}, "text": "A: เห้ย สมพรหรอ ได้ๆ ส่งเลขบัญชีมาเลยเพื่อน", "reaction": "แต๊งกิ้วมากมึง บัญชีชื่อ น.ส.สมศรี นะ (บัญชีแฟนกูเอง)"}, {"next": {"id": "callcenter-9-sub2", "msgs": ["ไหนๆ ก็ทักมาละ สนใจกู้เงินรายวันไหมเจ๊?"], "name": "มิจฉาชีพ (โป๊ะแตก)", "level": 9, "avatar": "🤡", "choices": [{"text": "A: สนใจค่ะ ดอกเบี้ยเท่าไหร่?", "memeDesc": "รอดมุกเพื่อนยืมเงิน มาตกม้าตายมุกเงินกู้", "memeIcon": "🤦‍♀️", "reaction": "มาทรงนี้ เสร็จโจรอีกรอบ", "isCorrect": false, "memeTitle": "DOUBLE TRAP"}, {"text": "B: จะแคปหน้าจอส่งตำรวจละนะ ไปไกลๆ", "memeDesc": "ด่ากลับแบบสวยๆ โจรหนีหางจุกตูด", "memeIcon": "💅", "reaction": "กลัวแล้วจ้าาา (หนี)", "isCorrect": true, "memeTitle": "SAVAGE"}], "category": "callcenter", "categoryTitle": ""}, "text": "B: สมพรไหนวะ กูเรียนโรงเรียนหญิงล้วน", "reaction": "เอ่อ... สงสัยกูจำผิดคน โทษทีๆ"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (23, 'phishing-3', 'phishing', '🔗 ฟิชชิ่ง & ลิงก์ดูดเงิน', 3, 'LINE Official (ปลอม)', '💬', 'data', '{"msgs": ["ฉลองครบรอบ 10 ปี LINE ประเทศไทย 🎉", "แจกสติกเกอร์โดราเอมอนดุ๊กดิ๊ก ฟรี!", "แอดไลน์และกดลิงก์นี้เพื่อรับเลย: bit.ly/free-line-sticker"], "choices": [{"next": {"id": "phishing-3-sub1", "msgs": ["และต้องส่งลิงก์นี้ต่อให้เพื่อนอีก 10 คนเพื่อปลดล็อก"], "name": "หน้าเว็บล็อกอินปลอม", "level": 3, "avatar": "🔑", "choices": [{"text": "A: กรอกรหัสและส่งต่อให้เพื่อนรัวๆ", "memeDesc": "เสียไลน์ไม่พอ พาเพื่อนซวยไปด้วย!", "memeIcon": "💥", "reaction": "(โดนแฮกไลน์เอาไปยืมเงินเพื่อนต่อ)", "isCorrect": false, "memeTitle": "CHAIN REACTION"}, {"text": "B: ทำไมแจกฟรีต้องให้ล็อกอินด้วย โหลดในแอปไลน์ปกติก็จบปะ", "memeDesc": "สติกเกอร์ฟรีที่ต้องแลกด้วยรหัสผ่าน คือสติกเกอร์โจร!", "memeIcon": "🙅‍♂️", "reaction": "(ไม่ได้สติกเกอร์ แต่ได้ความปลอดภัย)", "isCorrect": true, "memeTitle": "NO FREE LUNCH"}], "category": "phishing", "categoryTitle": ""}, "text": "A: โห อยากได้! กดเข้าไปรับเลย", "reaction": "กรุณาเข้าสู่ระบบด้วยอีเมลและรหัสผ่าน LINE เพื่อรับสติกเกอร์"}, {"text": "B: ไม่เอาอะ ซื้อเอง 50 คอยน์สบายใจกว่า", "memeDesc": "ยอมเสียเงินซื้อเอง ดีกว่าเสียบัญชีไลน์ให้แฮกเกอร์", "memeIcon": "💸", "reaction": "(ปลอดภัย 100%)", "isCorrect": true, "memeTitle": "PAY TO WIN"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (10, 'callcenter-10', 'callcenter', '📞 แก๊งคอลเซ็นเตอร์ & แอบอ้าง', 10, 'ศาลอาญาสูงสุด (ฝ่ายเร่งด่วน)', '⚖️', 'money', '{"msgs": ["เราขอแจ้งหมายจับฉบับที่ 45/2567 แจ้งไปยังคุณ...", "ศาลได้อนุมัติหมายจับคุณในข้อหา ''ค้ามนุษย์''", "กรุณากด 1 เพื่อฟังรายละเอียด หรือเตรียมตัวรับหมายค้นที่บ้าน"], "choices": [{"next": {"id": "callcenter-10-sub1", "msgs": ["ทางเราพบเงินโอนจากแก๊งค้ามนุษย์เข้าบัญชีคุณ 5 ล้านบาท", "เพื่อให้ศาลคุ้มครองชั่วคราว คุณต้องจ่ายเงินประกันตัว 50,000 บาททันที", "ห้ามวางสายเด็ดขาด ถตระเตรียมโอนผ่านแอปเดี๋ยวนี้"], "name": "สารวัตรสืบสวน", "level": 10, "avatar": "👨‍✈️", "choices": [{"text": "A: โอนให้หมดเลยครับ อย่าจับผมนะ!", "memeDesc": "บอสแก๊งคอลเซ็นเตอร์เอาชนะคุณได้!", "memeIcon": "☠️", "reaction": "รับทราบครับ ศาลปล่อยตัวคุณแล้ว (หรอ?)", "isCorrect": false, "memeTitle": "BOSS DEFEATED... YOU"}, {"text": "B: หมายจับบ้าอะไรโทรมาบอกก่อน? มาจับที่บ้านเลยมา", "memeDesc": "สติแข็งแกร่งดั่งหินผา! คุณเคลียร์หมวดนี้ได้แล้ว!", "memeIcon": "🏆", "reaction": "คุณท้าทายอำนาจศาลหรอ! ตู๊ดๆๆ...", "isCorrect": true, "memeTitle": "FINAL BOSS SLAIN"}], "category": "callcenter", "categoryTitle": ""}, "text": "A: (มือสั่นกด 1) มีเรื่องเข้าใจผิดแน่ๆ ครับ!", "reaction": "โอนสายไปยังสารวัตรสืบสวน... รอสักครู่"}, {"next": {"id": "callcenter-10-sub2", "msgs": ["ถ้าคุณยังเถียง ผมจะเพิ่มข้อหาหมิ่นประมาทศาลอีกคดี!"], "name": "มิจฉาชีพ (เริ่มสั่น)", "level": 10, "avatar": "🥵", "choices": [{"text": "A: ขอโทษครับๆ ยอมจ่ายค่าปรับให้จบเรื่อง", "memeDesc": "มาดีตลอด มาตกม้าตายตอนจบ!", "memeIcon": "📉", "reaction": "ดีมากครับ โอนมา 5,000 พอ (โล่งอก)", "isCorrect": false, "memeTitle": "ALMOST THERE"}, {"text": "B: ไปเรียนกฎหมายมาใหม่นะน้องนะ", "memeDesc": "ความรู้คืออาวุธ มิจฉาชีพแพ้ราบคาบ!", "memeIcon": "📜", "reaction": "ฝากไว้ก่อนเถอะมึง! (ปาโทรศัพท์ทิ้ง)", "isCorrect": true, "memeTitle": "LEGAL WEAPON"}], "category": "callcenter", "categoryTitle": ""}, "text": "B: ศาลอาญาสูงสุดไม่มีในประเทศไทยครับ มีแต่ศาลฎีกา", "reaction": "เอ่อ... ทางเราเปลี่ยนชื่อหน่วยงานใหม่ครับ!"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (11, 'scam-1', 'scam', '💸 หลอกลงทุน & ความรักบังตา', 1, 'โค้ชอเล็กซ์ (คริปโตพารวย)', '📈', 'money', '{"msgs": ["สวัสดีครับ สนใจให้เงินทำงานไหม?", "โปรเจกต์ใหม่ AI Trade กำไร 30% ใน 10 นาที!", "เริ่มต้นแค่ 500 บาท ถอนได้จริง 100%"], "choices": [{"next": {"id": "scam-1-sub1", "msgs": ["นี่ครับ รีวิวจากลูกศิษย์คนอื่น (ส่งรูปสลิปปลอม)", "โอนเข้าบัญชีแอดมินตอนนี้ แถมโบนัสเทรดฟรี 500 บาท!"], "name": "โค้ชอเล็กซ์", "level": 1, "avatar": "🤑", "choices": [{"text": "A: จัดไป 5,000 เลยค่ะโค้ช!", "memeDesc": "กำไรทิพย์! เงินจริงหายวับไปกับตา", "memeIcon": "📉", "reaction": "พอร์ตแตกแล้วครับ ต้องเติมเงินแก้พอร์ตด่วน!", "isCorrect": false, "memeTitle": "RUG PULL"}, {"text": "B: ถ้ากำไรดีขนาดนี้ โค้ชกู้มาลงเองสิ", "memeDesc": "เจ็บจี๊ด! ถามแทงใจดำมิจฉาชีพ", "memeIcon": "🎤", "reaction": "คุณพลาดโอกาสรวยแล้ว! (บล็อก)", "isCorrect": true, "memeTitle": "EMOTIONAL DAMAGE"}], "category": "scam", "categoryTitle": ""}, "text": "A: จริงเหรอคะ! สอนหนูหน่อย", "reaction": "ง่ายมากครับ แค่สมัครเว็บนี้แล้วเติมเงิน"}, {"next": {"id": "scam-1-sub2", "msgs": ["ถ้าแน่จริงก็ลองลงทุนสักหมื่นสิ จะได้รู้ว่าของจริง!"], "name": "โค้ชอเล็กซ์ (เริ่มหัวร้อน)", "level": 1, "avatar": "😤", "choices": [{"text": "A: เอ้า ท้าทายหรอ! โอนไปหมื่นนึงเลย", "memeDesc": "แพ้ภัยตัวเองเพราะความอีโก้!", "memeIcon": "🤡", "reaction": "ขอบคุณสำหรับเงินหมื่นนะไอ้หน้าโง่", "isCorrect": false, "memeTitle": "EGO TRAP"}, {"text": "B: เอาเลขบัญชีมึงไปให้ตำรวจเช็คดีกว่า", "memeDesc": "รวยด้วย ฉลาดด้วย โจรเกลียดสิ่งนี้!", "memeIcon": "💰", "reaction": "กรรม! (ปิดเฟซบุ๊กหนี)", "isCorrect": true, "memeTitle": "RICH & SMART"}], "category": "scam", "categoryTitle": ""}, "text": "B: ไม่ว่างครับ กำลังนับเงินที่มีอยู่", "reaction": "ขี้โม้! คนรวยจริงเขาไม่พูดหรอก"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (12, 'scam-2', 'scam', '💸 หลอกลงทุน & ความรักบังตา', 2, 'Capt. William (US Army)', '👱‍♂️', 'money', '{"msgs": ["Hello my beautiful queen. I am William from USA.", "I found 2 million dollars in Iraq war.", "I want to send this box to you, my future wife."], "choices": [{"next": {"id": "scam-2-sub1", "msgs": ["(ทักไลน์มา) แจ้งจากศุลกากร มีพัสดุจากต่างประเทศติดภาษี", "กรุณาโอนค่าภาษี 35,000 บาท เพื่อรับกล่องดอลลาร์ครับ"], "name": "ศุลกากร (ปลอม)", "level": 2, "avatar": "🛃", "choices": [{"text": "A: ที่รักรอแป๊บนะ กำลังโอนค่าภาษีให้!", "memeDesc": "ความรักบังตา... ภาษีทิพย์ก็มา", "memeIcon": "💔", "reaction": "William: Good girl. (หายไปพร้อมเงินภาษี)", "isCorrect": false, "memeTitle": "LOVE BLINDNESS"}, {"text": "B: แกะกล่องเอาดอลลาร์ในนั้นจ่ายค่าภาษีไปเลยสิ", "memeDesc": "เจอคนจริง ศุลกากรทิพย์ถึงกับไปไม่เป็น", "memeIcon": "🧠", "reaction": "Customs: เอ่อ... ทำไม่ได้ครับ มันผิดกฎ (แถ)", "isCorrect": true, "memeTitle": "LOOPHOLE"}], "category": "scam", "categoryTitle": ""}, "text": "A: Wow! Really? You trust me?", "reaction": "Yes, but the package is stuck at Thai Customs."}, {"next": {"id": "scam-2-sub2", "msgs": ["Please, just pay 500 THB for my internet bill.", "So we can keep talking."], "name": "William (Broken Heart)", "level": 2, "avatar": "😭", "choices": [{"text": "A: โธ่ น่าสงสาร โอนให้ 500 ละกัน", "memeDesc": "สงสารโจร สุดท้ายเราเดือดร้อนเอง", "memeIcon": "💸", "reaction": "Thank you fool! (บล็อก)", "isCorrect": false, "memeTitle": "PITY SCAM"}, {"text": "B: I only eat Pad Thai, no money for you.", "memeDesc": "ผัดไทยชนะทุกสิ่ง! โจรท้อแท้", "memeIcon": "🍜", "reaction": "Damn! (Blocked)", "isCorrect": true, "memeTitle": "PAD THAI SUPREMACY"}], "category": "scam", "categoryTitle": ""}, "text": "B: I don''t need your money, I have a sugar daddy.", "reaction": "What?! But I love you!"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (13, 'scam-3', 'scam', '💸 หลอกลงทุน & ความรักบังตา', 3, 'แอดมินฟ้า (หารายได้เสริม)', '👍', 'money', '{"msgs": ["รับสมัครคนกดไลค์ TikTok จ่ายคลิปละ 50 บาท!", "ทำที่บ้านได้ วันละ 500-1000 บาท สบายๆ", "สนใจพิมพ์ ''สนใจ'' เลยค่ะ"], "choices": [{"next": {"id": "scam-3-sub1", "msgs": ["ทำภารกิจแรกเสร็จ ถอนทุนคืนพร้อมกำไร 600 บาทได้ทันทีค่ะ", "มีรีวิวคนได้เงินจริงเพียบเลยนะคะ โอนเลยไหม?"], "name": "แอดมินฟ้า", "level": 3, "avatar": "📝", "choices": [{"text": "A: โอนค่ะ! อยากได้เงิน", "memeDesc": "งานง่ายไม่มีจริง มีแต่หลอกให้เติมเงินเพิ่ม!", "memeIcon": "🔄", "reaction": "ได้รับยอดแล้วค่ะ... ภารกิจต่อไปมัดจำ 3,000 นะคะ", "isCorrect": false, "memeTitle": "ENDLESS LOOP"}, {"text": "B: หักมัดจำจากค่าจ้างสิคะ", "memeDesc": "รู้ทันสเต็ปโกง ไม่เสียตังฟรี!", "memeIcon": "🧠", "reaction": "ไม่ได้ค่ะ ระบบไม่อนุญาต", "isCorrect": true, "memeTitle": "LOGIC STRIKES AGAIN"}], "category": "scam", "categoryTitle": ""}, "text": "A: สนใจค่ะ! ว่างงานพอดี", "reaction": "ยินดีด้วยค่ะ ขั้นแรกต้องโอนเงิน ''มัดจำรับงาน'' 500 บาทนะคะ"}, {"next": {"id": "scam-3-sub2", "msgs": ["ถ้าไม่เชื่อก็ลองเปิดใจดู ส่งเลขบัญชีมาเดี๋ยวโอนให้ฟรี 50 บาทก่อนเลย"], "name": "แอดมินฟ้า (เริ่มวีน)", "level": 3, "avatar": "💢", "choices": [{"text": "A: เอาดิ ส่งเลขบัญชีไปละ", "memeDesc": "ได้เงิน 50 บาท แต่ติดคุกฐานบัญชีม้า!", "memeIcon": "🐴", "reaction": "(โดนเอาเลขบัญชีไปแอบอ้างเป็นบัญชีม้า)", "isCorrect": false, "memeTitle": "MULE ACCOUNT"}, {"text": "B: ไม่เอาอะ ขี้เกียจกดไลค์", "memeDesc": "ความขี้เกียจช่วยรักษาทรัพย์สินไว้ได้!", "memeIcon": "🦥", "reaction": "คนขี้เกียจก็จนต่อไปเถอะ! (บล็อก)", "isCorrect": true, "memeTitle": "LAZY BUT SAFE"}], "category": "scam", "categoryTitle": ""}, "text": "B: กดไลค์บ้าอะไรคลิปละ 50 หลอกเด็กเถอะ", "reaction": "ไม่ได้หลอกนะคะ บริษัทเราจดทะเบียนถูกต้อง!"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (14, 'scam-4', 'scam', '💸 หลอกลงทุน & ความรักบังตา', 4, 'Mobile Center (หลุดจำนำ)', '📱', 'money', '{"msgs": ["🔥 โปรไฟไหม้! iPhone 15 Pro Max หลุดจำนำ", "สภาพ 99% ราคาเพียง 8,900 บาทเท่านั้น!!", "สินค้ามีชิ้นเดียว โอนก่อนได้ก่อนครับ"], "choices": [{"next": {"id": "scam-4-sub1", "msgs": ["ยอดเข้าแล้วครับ... แต่มีค่าประกันสินค้าสูญหายระหว่างขนส่งอีก 3,000", "พอของถึงบ้านแล้วจะโอนคืนให้ครับ"], "name": "Mobile Center", "level": 4, "avatar": "📦", "choices": [{"text": "A: อ๋อ ได้ครับ โอนไปละ", "memeDesc": "ของถูกเกินจริง มักจะไม่มีจริง!", "memeIcon": "👻", "reaction": "ขอบคุณครับ (เพจปลิวเรียบร้อย)", "isCorrect": false, "memeTitle": "GHOST SHOP"}, {"text": "B: เก็บปลายทางได้ไหมครับ?", "memeDesc": "เก็บเงินปลายทางคือเกราะป้องกันโจร!", "memeIcon": "📦", "reaction": "โปรนี้ไม่รับปลายทางครับพี่ (บล็อกหนี)", "isCorrect": true, "memeTitle": "COD SAVIOR"}], "category": "scam", "categoryTitle": ""}, "text": "A: เอาครับ! ขอเลขบัญชีเลย", "reaction": "เลขบัญชี 123-4-5678 นายสมชาย โอนแล้วแจ้งสลิปนะครับ"}, {"next": {"id": "scam-4-sub2", "msgs": ["(ส่งรูปบัตร ปชช. ที่ตัดต่อเนียนๆ มาให้) รีบหน่อยนะพี่ มีคิว 2 รอโอนอยู่"], "name": "Mobile Center (แถ)", "level": 4, "avatar": "📸", "choices": [{"text": "A: โห คิว 2 รออยู่ งั้นผมรีบโอนเลย", "memeDesc": "โจรชอบกดดันให้เรารีบโอน จะได้ไม่ทันคิด", "memeIcon": "🏃‍♂️", "reaction": "(จัดส่งลมไปให้)", "isCorrect": false, "memeTitle": "RUSHED MISTAKE"}, {"text": "B: เลขบัตรฟอนต์แปลกๆ นะ เอาไปเช็ค blacklistseller แป๊บ", "memeDesc": "เช็คประวัติคนโกงก่อนโอนเสมอ รอดชัวร์!", "memeIcon": "🔍", "reaction": "ไอ้หัวหมอ! (บล็อก)", "isCorrect": true, "memeTitle": "SMART BUYER"}], "category": "scam", "categoryTitle": ""}, "text": "B: ขอวิดีโอคอลดูของพร้อมบัตรประชาชนหน่อย", "reaction": "กล้องเสียครับพี่ ถ่ายรูปให้ดูแทนนะ"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (15, 'scam-5', 'scam', '💸 หลอกลงทุน & ความรักบังตา', 5, 'สมพร (เพื่อนสมัยประถม)', '👦', 'money', '{"msgs": ["เห้ยมึง สบายดีป่าววะ ไม่ได้คุยกันนานเลย", "จำกูได้ป่าว สมพรไง ที่เคยเตะบอลด้วยกัน", "พอดียายกูเข้าโรงบาล กูช็อตหนักมาก ขอยืมสัก 3,000 ได้ไหม"], "choices": [{"next": {"id": "scam-5-sub1", "msgs": ["โอนแล้วส่งสลิปมานะ เดี๋ยวเดือนหน้ากูรีบคืนให้พร้อมดอกเลย"], "name": "สมพร (ตัวปลอม)", "level": 5, "avatar": "👦", "choices": [{"text": "A: โอนละเพื่อน สู้ๆ นะเว้ย", "memeDesc": "เพื่อนก็ปลอม บัญชีก็ม้า!", "memeIcon": "🔪", "reaction": "ขอบใจมากโง่จังเพื่อนรัก (บล็อก)", "isCorrect": false, "memeTitle": "BETRAYED"}, {"text": "B: ทำไมชื่อบัญชีผู้หญิง? ขอวิดีโอคอลหน่อยดิ", "memeDesc": "เช็คให้ชัวร์ก่อนโอนให้เพื่อน (ที่ไม่ได้เจอนาน)", "memeIcon": "🕵️", "reaction": "กูอยู่ไอซียู หมอไม่ให้ใช้เสียง (แถ)", "isCorrect": true, "memeTitle": "TRUST ISSUES"}], "category": "scam", "categoryTitle": ""}, "text": "A: เห้ย สมพรหรอ ได้ๆ ส่งเลขบัญชีมา", "reaction": "แต๊งกิ้วมากมึง บัญชีชื่อ น.ส.สมศรี นะ (บัญชีแฟนกูเอง)"}, {"next": {"id": "scam-5-sub2", "msgs": ["ไหนๆ ก็ทักมาละ สนใจกู้เงินรายวันไหมเจ๊?"], "name": "มิจฉาชีพ (โป๊ะแตก)", "level": 5, "avatar": "🤡", "choices": [{"text": "A: สนใจค่ะ ดอกเบี้ยเท่าไหร่?", "memeDesc": "รอดมุกเพื่อนยืมเงิน มาตกม้าตายมุกเงินกู้", "memeIcon": "🤦‍♀️", "reaction": "มาทรงนี้ เสร็จโจรอีกรอบ", "isCorrect": false, "memeTitle": "DOUBLE TRAP"}, {"text": "B: จะแคปหน้าจอส่งตำรวจละนะ ไปไกลๆ", "memeDesc": "ด่ากลับแบบสวยๆ โจรหนีหางจุกตูด", "memeIcon": "💅", "reaction": "กลัวแล้วจ้าาา (หนี)", "isCorrect": true, "memeTitle": "SAVAGE"}], "category": "scam", "categoryTitle": ""}, "text": "B: สมพรไหนวะ กูเรียนโรงเรียนหญิงล้วน", "reaction": "เอ่อ... สงสัยกูจำผิดคน โทษทีๆ"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (16, 'scam-6', 'scam', '💸 หลอกลงทุน & ความรักบังตา', 6, 'ฝ่ายการตลาด (Major Cineplex)', '🍿', 'money', '{"msgs": ["ยินดีด้วย! คุณคือผู้โชคดีได้รับ ''ทองคำหนัก 1 บาท''", "จากการสุ่มแจกรางวัลลูกค้าที่ซื้อตั๋วหนังในเดือนนี้", "กรุณายืนยันสิทธิ์เพื่อรับของรางวัลค่ะ"], "choices": [{"next": {"id": "scam-6-sub1", "msgs": ["รบกวนโอนค่าภาษี 2,000 บาท เข้าบัญชีแอดมินนะคะ", "โอนปุ๊บ ส่งทองให้ปั๊บเลยค่ะ"], "name": "ฝ่ายการตลาด", "level": 6, "avatar": "🎫", "choices": [{"text": "A: ทองตั้ง 4 หมื่น จ่ายภาษี 2 พัน คุ้มมาก! โอนค่ะ", "memeDesc": "ความโลภบังตา จ่ายภาษีแต่ไม่ได้ทอง!", "memeIcon": "💰", "reaction": "(โดนบล็อกเรียบร้อย)", "isCorrect": false, "memeTitle": "GOLD DIGGER DEFEATED"}, {"text": "B: หักภาษีจากทองไปเลยสิคะ ส่งมาแค่เศษทองก็ได้", "memeDesc": "ต่อรองเก่ง โจรเถียงไม่ออก", "memeIcon": "🗣️", "reaction": "ไม่ได้ค่ะ บริษัทไม่มีนโยบายหักทองลูกค้า!", "isCorrect": true, "memeTitle": "SMART NEGOTIATOR"}], "category": "scam", "categoryTitle": ""}, "text": "A: กรี๊ด! ยืนยันสิทธิ์ค่ะ ต้องทำไงบ้าง?", "reaction": "ทางเราจะจัดส่งทองให้ฟรีค่ะ แต่มีค่าภาษีหัก ณ ที่จ่าย 5%"}, {"next": {"id": "scam-6-sub2", "msgs": ["อาจจะเป็นเบอร์เก่าคุณที่เคยใช้ค่ะ จะรับสิทธิ์ไหมคะ ถ้าไม่รับจะให้คนอื่น"], "name": "มิจฉาชีพ (ล่ก)", "level": 6, "avatar": "💦", "choices": [{"text": "A: เอ้ยๆ รับสิทธิ์ๆ กดผิดๆ", "memeDesc": "รู้ทันแล้วเชียว แต่สุดท้ายก็แพ้ความโลภ", "memeIcon": "😩", "reaction": "(เข้าสู่สเต็ปหลอกโอนค่าภาษีต่อ)", "isCorrect": false, "memeTitle": "WEAK MINDED"}, {"text": "B: ให้คนอื่นไปเลยจ้า ตามสบาย", "memeDesc": "หลบกระสุนมิจฉาชีพได้แบบเท่ๆ", "memeIcon": "😎", "reaction": "ชิ! โง่จริงๆ ของฟรีไม่เอา (วางสาย)", "isCorrect": true, "memeTitle": "BULLET DODGED"}], "category": "scam", "categoryTitle": ""}, "text": "B: ไม่ได้รับคิ้วหนังมา 2 ปีแล้วนะ จะสุ่มโดนได้ไง?", "reaction": "อ้าว... คุณคือเบอร์ 089-xxx-xxxx ใช่ไหมคะ?"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (17, 'scam-7', 'scam', '💸 หลอกลงทุน & ความรักบังตา', 7, 'พูลวิลล่าพัทยา ราคาถูก (เพจ)', '🏖️', 'money', '{"msgs": ["สวัสดีค่ะ พูลวิลล่า 4 ห้องนอน ติดทะเล", "คืนวันเสาร์นี้หลุดจอง 1 หลังค่ะ ลดพิเศษเหลือ 3,900 บาท!", "ราคานี้รวมปิ้งย่าง คาราโอเกะ สนใจจองไหมคะ?"], "choices": [{"next": {"id": "scam-7-sub1", "msgs": ["อ้อ มีค่าประกันความเสียหายอีก 2,000 ด้วยนะคะ", "โอนรวม 5,900 บาท คืนให้ตอนเช็คเอาท์ค่ะ"], "name": "เพจบ้านพักปลอม", "level": 7, "avatar": "🏠", "choices": [{"text": "A: โอเคค่ะ โอนให้แล้ว ไปทะเลกัน!", "memeDesc": "จองพูลวิลล่าทิพย์ ได้ไปนั่งร้องไห้ริมหาด!", "memeIcon": "😭", "reaction": "(ไปถึงพัทยา เจอแต่ที่ดินเปล่า)", "isCorrect": false, "memeTitle": "HOLIDAY RUINED"}, {"text": "B: ทำไมบัญชีรับโอนเป็นชื่อบุคคล ไม่ใช่ชื่อบริษัท?", "memeDesc": "เช็คชื่อบัญชีก่อนโอน เซฟเงินได้ชัวร์!", "memeIcon": "🚩", "reaction": "แอดมินใช้บัญชีส่วนตัวรับชั่วคราวค่ะ บัญชีบริษัทมีปัญหา", "isCorrect": true, "memeTitle": "RED FLAG ALERT"}], "category": "scam", "categoryTitle": ""}, "text": "A: สนใจมากค่ะ! โอนจองเลย", "reaction": "ยินดีค่ะ โอนเต็มจำนวนเพื่อล็อกบ้านนะคะ บัญชี นายโจร ใจร้าย"}, {"next": {"id": "scam-7-sub2", "msgs": ["ถ้าไม่รีบจอง มีลูกค้าอีกท่านรอโอนอยู่นะคะ จะหลุดคิวเอานะ"], "name": "แอดมินเพจ (หัวหมอ)", "level": 7, "avatar": "😈", "choices": [{"text": "A: งั้นโอนมัดจำไปก่อนครึ่งนึงละกัน", "memeDesc": "มัดจำครึ่งเดียว โจรก็เอา!", "memeIcon": "📉", "reaction": "(บล็อกหนีทันทีหลังจากได้มัดจำ)", "isCorrect": false, "memeTitle": "HALF SCAMMED"}, {"text": "B: งั้นให้คิวต่อไปเลยค่ะ เพจคนตามแค่หลักร้อย ไม่น่าไว้ใจ", "memeDesc": "ดูยอดคนตามเพจก่อนจอง ช่วยรอดตายได้!", "memeIcon": "🕵️‍♀️", "reaction": "เรื่องมากนักนะอีป้า! (บล็อกเราแทน)", "isCorrect": true, "memeTitle": "SHARP INVESTIGATOR"}], "category": "scam", "categoryTitle": ""}, "text": "B: ขอคอลดูบ้านพักตอนสดๆ ตอนนี้ได้ไหมคะ?", "reaction": "ตอนนี้แม่บ้านกำลังทำความสะอาด ไม่สะดวกคอลค่ะ"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (18, 'scam-8', 'scam', '💸 หลอกลงทุน & ความรักบังตา', 8, 'Nong Narak (ปล่อยบัตรคอน)', '🎤', 'money', '{"msgs": ["ปล่อยบัตรคอนเสิร์ต โซน VIP แถวหน้าสุด 1 ใบค่ะ", "เพื่อนเทไปไม่ได้ ขายราคาเท่าทุน 6,500 บาท", "นัดรับหน้างานได้เลยค่ะ สนใจเด็มมาน้า"], "choices": [{"next": {"id": "scam-8-sub1", "msgs": ["พอดีมีคนทักมาเยอะมาก ถ้าไม่มัดจำเค้าปล่อยให้คนอื่นนะคะ", "(ส่งรูปบัตรคอนเสิร์ตที่มีลายน้ำทับบางๆ มาให้ดู)"], "name": "Nong Narak", "level": 8, "avatar": "👩", "choices": [{"text": "A: โอนมัดจำเรียบร้อย เจอกันหน้าคอนนะคะ", "memeDesc": "นัดรับหน้างาน แต่มัดจำก่อน = เสี่ยง 99%!", "memeIcon": "🎫", "reaction": "(วันงานหายตัว ติดต่อไม่ได้ บล็อกหนี)", "isCorrect": false, "memeTitle": "CONCERT CANCELED"}, {"text": "B: ไปเจอกันหน้างานแล้วจ่ายเต็มเลย ไม่โอนมัดจำค่ะ", "memeDesc": "ไม่จ่ายก่อนเห็นของ โจรก็ทำอะไรไม่ได้", "memeIcon": "🛡️", "reaction": "งั้นผ่านก่อนนะคะ ไม่รับจองปากเปล่า (หนีไปหาเหยื่ออื่น)", "isCorrect": true, "memeTitle": "HARD TO GET"}], "category": "scam", "categoryTitle": ""}, "text": "A: ทักค่ะ! สนใจรับบัตร นัดรับหน้างานนะคะ", "reaction": "ได้เลยค่ะเตง แต่นัดรับหน้างานขอโอนมัดจำก่อน 2,000 น้า"}, {"next": {"id": "scam-8-sub2", "msgs": ["ถ้าเตงกลัวโกง งั้นวิดีโอคอลมาดูบัตรได้เลยค่ะ (ตั้งใจจะโชว์บัตรของคนอื่น)"], "name": "Nong Narak (แถ)", "level": 8, "avatar": "🙄", "choices": [{"text": "A: (วิดีโอคอลไปเห็นบัตรแว๊บๆ) โอเคเชื่อละ โอนมัดจำให้", "memeDesc": "เห็นบัตรจริง แต่คนขายไม่ใช่เจ้าของบัตร!", "memeIcon": "😵‍💫", "reaction": "(โดนโกงอยู่ดี เพราะบัตรนั้นขโมยรูปมา)", "isCorrect": false, "memeTitle": "ILLUSION"}, {"text": "B: วิดีโอคอลแล้วให้เอาบัตรแนบกับบัตร ปชช. ชู 3 นิ้วด้วยค่ะ", "memeDesc": "สั่งให้ทำท่าแปลกๆ คู่บัตร โจรปลอมรูปไม่ได้แน่นอน!", "memeIcon": "✌️", "reaction": "โรคจิตปะเนี่ย! (บล็อกหนี)", "isCorrect": true, "memeTitle": "VERIFICATION MASTER"}], "category": "scam", "categoryTitle": ""}, "text": "B: รหัสบัตรอะไรคะ ขอเอาไปเช็คในระบบก่อน", "reaction": "บัตรกระดาษค่ะ เช็คไม่ได้ ต้องดูของจริง"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (19, 'scam-9', 'scam', '💸 หลอกลงทุน & ความรักบังตา', 9, 'Oppa Ji-Hoon (Tinder Match)', '🧑🏻', 'money', '{"msgs": ["อันยองครับ ผมจีฮุนนะ เพิ่งย้ายมาทำงานที่ไทย", "คุณน่ารักจัง เราคุยกันมา 2 อาทิตย์แล้ว", "ผมรู้สึกดีกับคุณมากๆ เลยนะ"], "choices": [{"next": {"id": "scam-9-sub1", "msgs": ["ผมเล่นคริปโตได้กำไรมาเยอะมาก อยากสอนคุณเล่นจัง", "โหลดแอป ''CryptoWin'' สิ เดี๋ยวผมพากดแป๊บเดียวได้เงินไปกินข้าวกัน"], "name": "Oppa Ji-Hoon", "level": 9, "avatar": "🥺", "choices": [{"text": "A: ได้สิคะ โหลดแอปละ เติมเงินยังไงอะ?", "memeDesc": "หลอกให้รัก แล้วเชือดเอาเงิน (Pig Butchering Scam)", "memeIcon": "🐷", "reaction": "(โดนหลอกให้ลงทุนจนหมดตัว แล้วอปป้าก็หายไป)", "isCorrect": false, "memeTitle": "PIG BUTCHERING"}, {"text": "B: ไม่เล่นคริปโตค่ะ เล่นแต่สลากออมสิน", "memeDesc": "ความรักไม่ช่วยให้รวย เล่นสลากออมสินปลอดภัยกว่า!", "memeIcon": "🏦", "reaction": "โถ่... คุณไม่คิดจะสร้างอนาคตกับผมหรอ? (พยายามดราม่า)", "isCorrect": true, "memeTitle": "SAVINGS QUEEN"}], "category": "scam", "categoryTitle": ""}, "text": "A: เขินจัง อปป้าก็น่ารักเหมือนกันค่ะ", "reaction": "ผมมีเรื่องอยากให้คุณช่วยหน่อยครับ"}, {"next": {"id": "scam-9-sub2", "msgs": ["ผมอุตส่าห์อยากพาคุณรวยไปด้วยกัน ส่งลิงก์เทรด VIP ให้เลยนะเนี่ย"], "name": "Oppa Ji-Hoon (ดราม่า)", "level": 9, "avatar": "😢", "choices": [{"text": "A: อะๆ ลองดูก็ได้ สัก 1,000 นึง", "memeDesc": "ใจแข็งมาตลอด มาแพ้ลูกอ้อนซะงั้น", "memeIcon": "🫠", "reaction": "(เงินหายวับไปกับตา)", "isCorrect": false, "memeTitle": "MIND CONTROLLED"}, {"text": "B: รวยคนเดียวไปเถอะพ่อหนุ่ม ปัดทิ้งละนะ", "memeDesc": "ปัดซ้ายให้คนแปลกหน้าที่ชวนลงทุน!", "memeIcon": "👈", "reaction": "เดี๋ยวสิครับคุณ! (เรากดอันแมตช์)", "isCorrect": true, "memeTitle": "SWIPE LEFT"}], "category": "scam", "categoryTitle": ""}, "text": "B: คุยตั้งนานไม่ยอมนัดเจอ ตัวปลอมปะเนี่ย", "reaction": "ผมยุ่งกับธุรกิจจริงๆ ครับ ไม่เชื่อใจผมหรอ?"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (20, 'scam-10', 'scam', '💸 หลอกลงทุน & ความรักบังตา', 10, 'มูลนิธิหมาแมวสัญจร (เพจ)', '🐶', 'money', '{"msgs": ["ด่วน! น้องหมาถูกรถชนต้องการเลือดและค่าผ่าตัด 20,000 บาท", "ตอนนี้น้องอาการสาหัสมาก ขาดอีกแค่ 3,000 บาทเท่านั้น", "ช่วยสมทบทุนต่อลมหายใจให้น้องด้วยนะคะ 😭"], "choices": [{"next": {"id": "scam-10-sub1", "msgs": ["(ส่งรูปหมาใส่สายน้ำเกลือที่ก๊อปมาจากเน็ต) รบกวนส่งสลิปด้วยนะคะ"], "name": "มูลนิธิหมาแมว", "level": 10, "avatar": "🐱", "choices": [{"text": "A: โอนเรียบร้อยค่ะ ขอให้น้องปลอดภัยนะ", "memeDesc": "ทำบุญบูชาโทษ โอนเงินให้โจรใจบาป!", "memeIcon": "💸", "reaction": "(เงินเข้ากระเป๋ามิจฉาชีพ ไม่ได้ไปช่วยหมา)", "isCorrect": false, "memeTitle": "FAKE CHARITY"}, {"text": "B: ทำไมชื่อบัญชีเป็นบุคคลธรรมดา ไม่ใช่ชื่อมูลนิธิ?", "memeDesc": "ทำบุญต้องมีสติ เช็คชื่อบัญชีก่อนเสมอ", "memeIcon": "🧐", "reaction": "แอดมินเป็นคนจัดการค่าใช้จ่ายให้น้องโดยตรงค่ะ!", "isCorrect": true, "memeTitle": "SUSPICIOUS SAINT"}], "category": "scam", "categoryTitle": ""}, "text": "A: สงสารน้องจัง โอนช่วย 500 บาทค่ะ", "reaction": "ขอบคุณแทนน้องด้วยนะคะ โอนเข้าบัญชี ''น.ส. แอบอ้าง หากิน'' ได้เลยค่ะ"}, {"next": {"id": "scam-10-sub2", "msgs": ["แต่คลินิกปิดรับสายแล้วนะคะ โอนผ่านทางเพจสะดวกกว่าค่ะ รบกวนช่วยน้องด่วนๆ"], "name": "แอดมินเพจ (เหงื่อตก)", "level": 10, "avatar": "💧", "choices": [{"text": "A: กลัวน้องตาย โอนผ่านเพจไปก่อนละกัน", "memeDesc": "ใช้ความสงสารมากดดัน คือไม้ตายของโจร", "memeIcon": "😿", "reaction": "(เสร็จโจรตามระเบียบ)", "isCorrect": false, "memeTitle": "EMOTIONAL HIJACK"}, {"text": "B: งั้นพรุ่งนี้เช้าคลินิกเปิด เดี๋ยวผมโอนตรงเข้าคลินิกเอง", "memeDesc": "ช่วยด้วยสติ ไม่โดนโจรหลอกใช้ความใจดี!", "memeIcon": "🦸‍♂️", "reaction": "คนใจดำ! ปล่อยน้องตาย! (ด่าแล้วบล็อก)", "isCorrect": true, "memeTitle": "RATIONAL SAVIOR"}], "category": "scam", "categoryTitle": ""}, "text": "B: น้องรักษาอยู่คลินิกไหนคะ เดี๋ยวโทรไปเช็ค", "reaction": "คลินิกรักษาสัตว์รักดี ค่ะ แถวๆ ชลบุรี"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (21, 'phishing-1', 'phishing', '🔗 ฟิชชิ่ง & ลิงก์ดูดเงิน', 1, 'สินเชื่อฉับไว (อนุมัติง่าย)', '🏦', 'data', '{"msgs": ["ร้อนเงินมั้ย? กู้ได้ทันที 50,000 บาท!", "ไม่เช็คบูโร แค่กดลิงก์โหลดแอปนี้: bit.ly/fast-money-apk"], "choices": [{"text": "A: กำลังช็อตพอดี! โหลดเลย", "memeDesc": "กู้หลักพัน ดอกหลักแสน แถมโดนประจาน!", "memeIcon": "📱", "reaction": "(ดูดข้อมูลเกลี้ยง + โทรทวงประจาน)", "isCorrect": false, "memeTitle": "DATA LEAK!"}, {"text": "B: ดอกเบี้ยโหดมั้ย? ไม่โหลดมั่วซั่วหรอก", "memeDesc": "ไม่โหลดแอปเถื่อน ปลอดภัยที่สุด", "memeIcon": "⚖️", "reaction": "เรื่องมากจังวะ (ไม่คุยด้วย)", "isCorrect": true, "memeTitle": "LAWYER STYLE"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (22, 'phishing-2', 'phishing', '🔗 ฟิชชิ่ง & ลิงก์ดูดเงิน', 2, 'K-Bank (ระบบอัตโนมัติ SMS)', '🏦', 'data', '{"msgs": ["แอปพลิเคชัน K-PLUS ของท่านหมดอายุการใช้งาน", "เพื่อป้องกันบัญชีถูกล็อก กรุณาอัปเดตระบบทันที", "คลิก: www.kbank-update-security.com"], "choices": [{"next": {"id": "phishing-2-sub1", "msgs": ["กรุณากรอก Username, Password และเลขบัตร ปชช. เพื่อเข้าสู่ระบบ"], "name": "หน้าเว็บปลอม", "level": 2, "avatar": "🌐", "choices": [{"text": "A: กรอกข้อมูลให้ครบ จะได้รีบอัปเดต", "memeDesc": "กรอกรหัสผ่านในเว็บปลอม = มอบกุญแจเซฟให้โจร!", "memeIcon": "🎣", "reaction": "(เงินถูกโอนออกหมดบัญชีภายใน 1 นาที)", "isCorrect": false, "memeTitle": "PHISHED"}, {"text": "B: เอ๊ะ ทำไม URL ไม่ใช่เว็บธนาคารหลัก ปิดทิ้งดีกว่า", "memeDesc": "เช็ค URL ทุกครั้งก่อนพิมพ์รหัสผ่าน!", "memeIcon": "🕵️", "reaction": "(รอดพ้นจากการถูกแฮก)", "isCorrect": true, "memeTitle": "URL INSPECTOR"}], "category": "phishing", "categoryTitle": ""}, "text": "A: ตกใจ! รีบกดลิงก์เข้าไปอัปเดต", "reaction": "(เปิดเว็บหน้าตาเหมือนของธนาคารเป๊ะ)"}, {"text": "B: โหลดแอปอัปเดตผ่าน App Store / Play Store เองดีกว่า", "memeDesc": "อัปเดตแอปผ่าน Store ทางการ ปลอดภัย 100%", "memeIcon": "✅", "reaction": "...", "isCorrect": true, "memeTitle": "SAFE ZONE"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (24, 'phishing-4', 'phishing', '🔗 ฟิชชิ่ง & ลิงก์ดูดเงิน', 4, 'System Security Popup', '⚠️', 'data', '{"msgs": ["⚠️ โทรศัพท์ของคุณติดไวรัสทรอจัน 5 ตัว!", "รูปภาพและแอปธนาคารกำลังถูกขโมยข้อมูล", "กดปุ่ม ''ล้างไวรัสเดี๋ยวนี้'' เพื่อติดตั้งแอป Anti-Virus"], "choices": [{"next": {"id": "phishing-4-sub1", "msgs": ["เพื่อการสแกนที่ล้ำลึก กรุณากดอนุญาตการเข้าถึง ''การช่วยเหลือพิเศษ (Accessibility)''"], "name": "แอปเถื่อน", "level": 4, "avatar": "👾", "choices": [{"text": "A: อนุญาตให้หมดเลย รีบล้างไวรัสที", "memeDesc": "แอปสแกนไวรัสนี่แหละ ตัวไวรัสของจริง!", "memeIcon": "🤖", "reaction": "(โดนรีโมทควบคุมหน้าจอ โอนเงินเกลี้ยง)", "isCorrect": false, "memeTitle": "REMOTE CONTROLLED"}, {"text": "B: เอ๊ะ ไปโหลดแอปใน Play Store ชัวร์กว่า", "memeDesc": "ไม่ติดตั้งไฟล์จากนอก Store ปลอดภัยสุด", "memeIcon": "🛡️", "reaction": "(ลบไฟล์ .apk ทิ้ง ปลอดภัย)", "isCorrect": true, "memeTitle": "NICE SAVE"}], "category": "phishing", "categoryTitle": ""}, "text": "A: ตกใจ! รีบกดติดตั้งแอปสแกนไวรัสด่วน", "reaction": "กำลังดาวน์โหลดไฟล์ cleaner.apk..."}, {"text": "B: ป๊อปอัปหลอกเด็ก ปิดแท็บเว็บนี้ทิ้งดีกว่า", "memeDesc": "เว็บแจ้งเตือนไวรัส = มุกหากินคลาสสิก ปิดทิ้งได้เลย", "memeIcon": "❌", "reaction": "(หน้าต่างแจ้งเตือนหายไป)", "isCorrect": true, "memeTitle": "IGNORE MASTER"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (25, 'phishing-5', 'phishing', '🔗 ฟิชชิ่ง & ลิงก์ดูดเงิน', 5, 'กรมการค้าภายใน (DIT)', '🏛️', 'data', '{"msgs": ["คุณได้รับสิทธิ์ร้านค้าธงฟ้าประชารัฐ", "รับเงินอุดหนุน 2,000 บาท/เดือน", "แอดไลน์เจ้าหน้าที่เพื่อรับสิทธิ์: @dit-support"], "choices": [{"next": {"id": "phishing-5-sub1", "msgs": ["(ส่งลิงก์โหลดไฟล์ .apk มาให้) ติดตั้งแล้วสแกนใบหน้าเพื่อยืนยันตัวตนนะครับ"], "name": "เจ้าหน้าที่ปลอม", "level": 5, "avatar": "👨‍💻", "choices": [{"text": "A: ทำตามขั้นตอน สแกนหน้าเรียบร้อย", "memeDesc": "แอปเถื่อน + สแกนหน้า = เตรียมบอกลาเงินในบัญชี", "memeIcon": "💸", "reaction": "(โดนดูดเงินหมดบัญชีตอนเผลอ)", "isCorrect": false, "memeTitle": "BIOMETRIC HACK"}, {"text": "B: ทำไมไม่ให้โหลดใน App Store ล่ะ?", "memeDesc": "แอปราชการต้องอยู่ใน Store เท่านั้น!", "memeIcon": "🤔", "reaction": "แอปยังไม่ขึ้น Store ครับ รบกวนโหลดผ่านลิงก์ก่อน", "isCorrect": true, "memeTitle": "SUSPICIOUS"}], "category": "phishing", "categoryTitle": ""}, "text": "A: แอดไลน์ไปเลยจ้า อยากได้เงินอุดหนุน", "reaction": "เจ้าหน้าที่: สวัสดีครับ โหลดแอป ''ทางรัฐ (เวอร์ชั่นอัปเดต)'' จากลิงก์นี้ครับ"}, {"text": "B: ไม่ได้ลงทะเบียนร้านค้าไว้ จะได้สิทธิ์ได้ไง?", "memeDesc": "ไม่เคยลงทะเบียน แต่อยู่ๆ ได้สิทธิ์ = หลอกลวงชัวร์", "memeIcon": "🧠", "reaction": "(ไม่สนใจข้อความ มิจฉาชีพทำอะไรไม่ได้)", "isCorrect": true, "memeTitle": "LOGIC WON"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (26, 'phishing-6', 'phishing', '🔗 ฟิชชิ่ง & ลิงก์ดูดเงิน', 6, 'Thai Airways (โปรโมชั่น)', '✈️', 'data', '{"msgs": ["ร่วมตอบแบบสอบถามประเมินการบริการของการบินไทย", "รับฟรี! บัตรกำนัลสตาร์บัคส์ 500 บาท", "คลิกตอบเลย: www.thaiair-survey-reward.com"], "choices": [{"next": {"id": "phishing-6-sub1", "msgs": ["ยอดชำระ 20.00 THB", "รอรับรหัส OTP ทาง SMS เพื่อยืนยันการชำระเงิน"], "name": "หน้าเว็บจ่ายเงินปลอม", "level": 6, "avatar": "💳", "choices": [{"text": "A: ยอมจ่าย 20 บาท กรอก OTP รัวๆ", "memeDesc": "จ่ายค่าส่ง 20 บาท แต่โดนรูดบัตรไปสองหมื่น!", "memeIcon": "☕", "reaction": "(SMS เข้าว่าโดนรูดไป 20,000 ไม่ใช่ 20 บาท!)", "isCorrect": false, "memeTitle": "EXPENSIVE COFFEE"}, {"text": "B: แจกฟรีทำไมต้องเก็บค่าส่งด้วยบัตรเครดิต? ปิดเว็บดีกว่า", "memeDesc": "เอะใจเรื่องค่าส่ง ช่วยเซฟเงินก้อนโตได้", "memeIcon": "🛡️", "reaction": "(รอดตัวไป)", "isCorrect": true, "memeTitle": "SMART MOVE"}], "category": "phishing", "categoryTitle": ""}, "text": "A: ตอบคำถามแป๊บเดียว ได้กาแฟฟรี เอาสิ", "reaction": "ขอบคุณที่ตอบแบบสอบถาม กรุณากรอกที่อยู่และ ''เบอร์บัตรเครดิต'' เพื่อจ่ายค่าส่งบัตรกำนัล 20 บาท"}, {"text": "B: เอาเว็บแปลกๆ มาหลอกอีกละ บล็อกจ้า", "memeDesc": "แค่เห็นชื่อเว็บแปลกๆ ก็รู้ทันแล้ว", "memeIcon": "😎", "reaction": "(รอดตัวไปชิลๆ)", "isCorrect": true, "memeTitle": "TOO SMART FOR THIS"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (27, 'phishing-7', 'phishing', '🔗 ฟิชชิ่ง & ลิงก์ดูดเงิน', 7, 'AirAsia Alert', '🛫', 'data', '{"msgs": ["เที่ยวบิน FD3025 ของคุณถูกยกเลิก!", "กรุณากดลิงก์เพื่อทำเรื่องขอคืนเงิน (Refund)", "หรือเปลี่ยนเที่ยวบินด่วนภายใน 2 ชม."], "choices": [{"next": {"id": "phishing-7-sub1", "msgs": ["(เว็บหน้าตาเหมือนจริงมาก แต่ URL แปลกๆ)"], "name": "หน้าล็อกอินปลอม", "level": 7, "avatar": "🔑", "choices": [{"text": "A: รีบกรอกรหัสผ่าน เดี๋ยวเปลี่ยนไฟลท์ไม่ทัน", "memeDesc": "ตกใจกลัวตกเครื่อง จนลืมดูว่าเว็บปลอม!", "memeIcon": "😱", "reaction": "(โดนแฮกเฟซบุ๊กเอาไปหลอกยืมเงินเพื่อน)", "isCorrect": false, "memeTitle": "PANIC LOGIN"}, {"text": "B: โทรเข้า Call Center สายการบินตรงๆ ดีกว่า", "memeDesc": "เช็คข้อมูลจากช่องทางหลัก ปลอดภัยที่สุด", "memeIcon": "☎️", "reaction": "Call Center: เที่ยวบินยังบินปกตินะคะ", "isCorrect": true, "memeTitle": "DOUBLE CHECK"}], "category": "phishing", "categoryTitle": ""}, "text": "A: อ้าว พรุ่งนี้จะบินแล้ว! รีบกดเข้าไปดู", "reaction": "กรุณาล็อกอินผ่าน Facebook หรืออีเมลเพื่อยืนยันตัวตน"}, {"text": "B: เดือนนี้ฉันไม่ได้จองตั๋วไปไหนเลยนะ มั่วละ", "memeDesc": "คนไม่ได้บิน จะโดนเลื่อนไฟลท์ได้ไงเล่า!", "memeIcon": "🛋️", "reaction": "(ไม่สนใจ ปล่อยผ่าน)", "isCorrect": true, "memeTitle": "STAY HOME SAFE"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (28, 'phishing-8', 'phishing', '🔗 ฟิชชิ่ง & ลิงก์ดูดเงิน', 8, 'ตำรวจจราจร (SMS)', '🚦', 'money', '{"msgs": ["คุณมีใบสั่งค้างชำระ (ขับรถเร็วเกินกำหนด)", "โปรดชำระค่าปรับ 500 บาท ภายในวันนี้เพื่อหลีกเลี่ยงการอายัดทะเบียน", "ชำระผ่านเว็บ: e-ticket-police-online.com"], "choices": [{"next": {"id": "phishing-8-sub1", "msgs": ["ระบบรองรับเฉพาะบัตรเครดิตและเดบิตเท่านั้น"], "name": "เว็บจ่ายค่าปรับ(ปลอม)", "level": 8, "avatar": "💳", "choices": [{"text": "A: กรอกข้อมูลบัตรและรหัสหลังบัตร", "memeDesc": "ค่าปรับ 500 แต่โดนโจรปรับไป 3 หมื่น!", "memeIcon": "🏎️", "reaction": "(โดนเอาข้อมูลบัตรไปรูดซื้อเกมออนไลน์ 3 หมื่น)", "isCorrect": false, "memeTitle": "SPEEDING TICKET TO HELL"}, {"text": "B: ปกติใบสั่งสแกนจ่ายคิวอาร์โค้ดผ่านแอปแบงก์ได้นิ เว็บนี้แปลกๆ", "memeDesc": "รู้ระบบจ่ายค่าปรับจริง โจรก็หลอกไม่ได้", "memeIcon": "👮", "reaction": "(ปิดเว็บทิ้ง รอดตัวไป)", "isCorrect": true, "memeTitle": "RULE KNOW-HOW"}], "category": "phishing", "categoryTitle": ""}, "text": "A: ซวยละ! เมื่อวานเพิ่งเหยียบ 120 กดลิงก์ไปจ่ายดีกว่า", "reaction": "กรุณากรอกข้อมูลบัตรเครดิตเพื่อชำระค่าปรับ"}, {"text": "B: ผมไม่มีรถยนต์ครับ นั่งแต่รถเมล์", "memeDesc": "คนไม่มีรถ โดนใบสั่งความเร็วได้ไง!", "memeIcon": "🚌", "reaction": "(รอดจากการหลอกลวง)", "isCorrect": true, "memeTitle": "BUS RIDER"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (29, 'phishing-9', 'phishing', '🔗 ฟิชชิ่ง & ลิงก์ดูดเงิน', 9, 'ฝ่ายความปลอดภัย Cyber Security', '🛡️', 'data', '{"msgs": ["แจ้งเตือนด่วน! ข้อมูลของคุณหลุดไหลใน Dark Web", "กรุณาโหลดแอป ''SafeGuard Pro'' ทันทีเพื่อล็อกบัญชีธนาคารทั้งหมด", "หากเพิกเฉย เงินคุณอาจหายได้ในคืนนี้"], "choices": [{"next": {"id": "phishing-9-sub1", "msgs": ["เพื่อใช้ในการดักจับรหัส OTP ที่แฮกเกอร์อาจขอเข้ามา"], "name": "SafeGuard (แอปเถื่อน)", "level": 9, "avatar": "📱", "choices": [{"text": "A: ฟังดูมีเหตุผล กด ''อนุญาต'' สิทธิ์ SMS", "memeDesc": "โหลดแอปมากันแฮกเกอร์ แต่แอปนั่นแหละคือแฮกเกอร์!", "memeIcon": "🤦", "reaction": "(มิจฉาชีพเอาสิทธิ์ไปอ่านรหัส OTP และโอนเงินออกหมดบัญชี)", "isCorrect": false, "memeTitle": "IRONIC SECURITY"}, {"text": "B: แอปกันแฮกอะไรขออ่าน SMS ส่วนตัว ไม่ให้หรอก ลบทิ้ง!", "memeDesc": "ไม่ให้สิทธิ์เข้าถึงข้อมูลส่วนตัว ปลอดภัยชัวร์", "memeIcon": "🔒", "reaction": "(ลบแอปทิ้ง ปลอดภัย)", "isCorrect": true, "memeTitle": "PRIVACY FIRST"}], "category": "phishing", "categoryTitle": ""}, "text": "A: น่ากลัวมาก! รีบกดโหลดแอปเลย", "reaction": "แอป SafeGuard Pro ขอสิทธิ์เข้าถึงข้อความ SMS ของคุณ"}, {"text": "B: หลอกให้โหลดแอปดูดเงินอีกละสิ ไม่เนียนไปเรียนมาใหม่", "memeDesc": "มุกเก่าแล้วจ้า หลอกคนมีสติไม่ได้หรอก", "memeIcon": "🥱", "reaction": "(เมินข้อความ)", "isCorrect": true, "memeTitle": "TOO EXPERIENCED"}]}');
INSERT INTO public.chat_scenario (cs_id, scenario_id, category, "categoryTitle", level, name, avatar, "lossType", content) VALUES (30, 'phishing-10', 'phishing', '🔗 ฟิชชิ่ง & ลิงก์ดูดเงิน', 10, 'เบอร์แปลก (ส่ง SMS)', '💌', 'data', '{"msgs": ["ขอเชิญร่วมงานแต่งงานของเรา (สมชาย & ฟ้า)", "วันเสาร์นี้ที่โรงแรม แกรนด์ พลาซ่า", "เปิดดูการ์ดเชิญและแผนที่ได้ที่นี่: wedding-invite.apk"], "choices": [{"next": {"id": "phishing-10-sub1", "msgs": ["เพื่อติดตั้งแอปพลิเคชันนี้", "กรุณาไปที่การตั้งค่า และเปิด ''อนุญาตให้ติดตั้งแอปจากแหล่งที่ไม่รู้จัก''"], "name": "System Installer", "level": 10, "avatar": "⚙️", "choices": [{"text": "A: อยากรู้ว่าใครแต่งงาน กดเปิดสิทธิ์และติดตั้งเลย!", "memeDesc": "งานแต่งทิพย์ ดูดเงินจริง! บอสฟิชชิ่งเอาชนะคุณได้", "memeIcon": "💀", "reaction": "(หน้าจอมือถือค้าง... เงินในบัญชีถูกโอนออกไป 500,000 บาท)", "isCorrect": false, "memeTitle": "THE WEDDING CRASHER"}, {"text": "B: เห้ย นามสกุล .apk มันคือแอปติดตั้ง นี่ไม่ใช่รูปภาพการ์ดเชิญ ลบทิ้งด่วน!", "memeDesc": "สติและไหวพริบยอดเยี่ยม! คุณเคลียร์ด่านฟิชชิ่งทั้งหมดได้แล้ว!", "memeIcon": "🏆", "reaction": "(ลบไฟล์ทิ้ง มือถือปลอดภัย 100%)", "isCorrect": true, "memeTitle": "MALWARE SLAYER"}], "category": "phishing", "categoryTitle": ""}, "text": "A: สมชายไหนวะ? ลองกดเปิดดูหน่อยละกัน", "reaction": "ไฟล์ถูกดาวน์โหลดแล้ว... คุณต้องการติดตั้ง ''Wedding_Invite.apk'' หรือไม่?"}, {"next": {"id": "phishing-10-sub2", "msgs": ["มิจฉาชีพสมัยนี้เปลี่ยนจากการส่งลิงก์เว็บ มาเป็นการส่งไฟล์แอปเถื่อน (.apk) แล้ว"], "name": "ความคิดในหัวคุณ", "level": 10, "avatar": "🧠", "choices": [{"text": "A: ลองโหลดมาแงะโค้ดดูหน่อยดีกว่าว่ามันทำงานยังไง", "memeDesc": "ความอยากรู้อยากเห็น ฆ่าแมว (และเงินในบัญชี) ได้เสมอ!", "memeIcon": "🐈", "reaction": "(เผลอกดรันไฟล์ มัลแวร์ทำงาน ดูดข้อมูลเกลี้ยง)", "isCorrect": false, "memeTitle": "CURIOSITY KILLED THE CAT"}, {"text": "B: บล็อกเบอร์นี้ทิ้ง ลบข้อความไปเลย ปลอดภัยสุด", "memeDesc": "ไม่ยุ่งกับไฟล์แปลกปลอม คือการป้องกันขั้นสูงสุด!", "memeIcon": "🛡️", "reaction": "(รอดพ้นภัยไซเบอร์อย่างสวยงาม)", "isCorrect": true, "memeTitle": "ULTIMATE SHIELD"}], "category": "phishing", "categoryTitle": ""}, "text": "B: ถ้าเป็นเพื่อนเราจริง ต้องทักไลน์มาสิ ไม่ใช่ส่ง SMS เบอร์แปลก", "reaction": "..."}]}');
